	/*************************
		Ebit Calculator
	 *************************/
	function ebit($request)
	{
		if (is_numeric($request->x) && is_numeric($request->y)) {
			$ebit = $request->x - $request->y;
			$this->param['ebit'] = $ebit;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}
