		$vat = $request->vat;
		$method = $request->method;
		$amount = $request->amount;
		if ($method == 'add') {
			$net = $request->amount;
			$vatAmount = $vat * $amount / 100;
			$gross = $amount + $vatAmount;
		} else {
			$gross = $request->amount;
			$vat = 1 + ($vat / 100);
			$net = round($amount / $vat, 2);
			$vatAmount = $amount - $net;
		}

		// alerts
		if (empty($fieldsDone)) {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		if (empty($numeric)) {
			$this->param['error'] = 'Invalid Input.';
			return $this->param;
		}
		// return values

		$this->param['vatAmount'] = $vatAmount;
		$this->param['net'] = $net;
		$this->param['gross'] = $gross;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	/*************************
		salary Calculator
	 *************************/
	function salary($request)
	{
	// dd($request->all());
		if (is_numeric($request->salary) && is_numeric($request->hours)) {
			$salary = $request->salary;
			$week_hours = $request->hours;
			$week_day = $request->days;
			$yearly_hours = $week_hours * 52;
			$daily_hours = $week_hours / $week_day;


			if ($request->per === 'Hourly') {
				$hourly = $salary;
				$daily = round($salary * $daily_hours, 2);
				$week = round($week_hours * $salary);
				$bi_week = round($week * 2);
				$yearly = round($yearly_hours * $salary);
				$monthly = round($yearly / 12);
				$sami_month = round($monthly / 2);
				$quarterly = round($yearly / 4);
			} elseif ($request->per === 'Daily') {
				$daily = $salary;
				$hourly = round($salary / $daily_hours, 2);
				$week = round($week_hours * $hourly);
				$bi_week = round($week * 2);
				$yearly = round($yearly_hours * $hourly);
				$monthly = round($yearly / 12);
				$sami_month = round($monthly / 2);
				$quarterly = round($yearly / 4);
			} elseif ($request->per === 'Weekly') {
				$a_week = $salary;
				$a_hourly = round($a_week / $week_hours, 2);
				$a_daily = round($a_hourly * $daily_hours, 2);
				$a_bi_week = round($a_week * 2);
				$a_yearly = round($yearly_hours * $a_hourly);
				$a_monthly = round($a_yearly / 12);
				$a_sami_month = round($a_monthly / 2);
				$a_quarterly = round($a_yearly / 4);
			} elseif ($request->per === 'Bi-Weekly') {
				$a_bi_week = $salary;
				$a_week = round($a_bi_week * 2);
				$a_hourly = round($a_week / $week_hours, 2);
				$a_daily = round($a_hourly * $daily_hours, 2);
				$a_yearly = round($yearly_hours * $a_hourly);
				$a_monthly = round($a_yearly / 12);
				$a_sami_month = round($a_monthly / 2);
				$a_quarterly = round($a_yearly / 4);
			} elseif ($request->per === 'Semi-Monthly') {
				$a_sami_month = $salary;
				$a_monthly = round($a_sami_month * 2);
				$a_yearly = round($a_monthly * 12);
				$a_quarterly = round($a_yearly / 4);
				$a_hourly = round($a_yearly / $yearly_hours, 2);
				$a_daily = round($a_hourly * $daily_hours, 2);
				$a_week = round($week_hours * $a_daily);
				$a_bi_week = round($a_week * 2);
			} elseif ($request->per === 'Monthly') {
				$a_yearly = round($salary * 12);
				$a_quarterly = round($a_yearly / 4);
				$a_sami_month = round($salary / 2);
				$a_hourly = round($a_yearly / $yearly_hours, 2);
				$a_week = round($week_hours * $a_hourly);
				$a_bi_week = round($a_week * 2);
				$a_daily = round($a_hourly * $daily_hours, 2);
				$a_monthly = $salary;
			} elseif ($request->per === 'Quarterly') {
				$a_quarterly = $salary;
				$a_yearly = round($a_quarterly * 4);
				$a_hourly = round($a_yearly / $yearly_hours, 2);
				$a_daily = round($a_hourly * $daily_hours, 2);
				$a_week = round($week_hours * $a_daily);
				$a_bi_week = round($a_week * 2);
				$a_monthly = round($a_yearly / 12);
				$a_sami_month = round($a_monthly / 2);
			} elseif ($request->Annual) {
				$a_yearly = $salary;
				$a_hourly = round($a_yearly / $yearly_hours, 2);
				$a_daily = round($a_hourly * $daily_hours, 2);
				$a_week = round($week_hours * $a_hourly);
				$a_bi_week = round($a_week * 2);
				$a_monthly = round($a_yearly / 12);
				$a_sami_month = round($a_monthly / 2);
				$a_quarterly = round($a_yearly / 4);
			}





			$holidays = $vacation = 0;
			if (is_numeric($request->holidays)) {
				$holidays = $request->holidays;
			}
			if (is_numeric($request->vacation)) {
				$vacation = $request->vacation;
			}
			$total_leaves = $holidays + $vacation;
			if ($total_leaves != 0) {
				if ($request->per == 'Hourly' || $request->per == 'Daily') {
					$sub_salary = $daily * $total_leaves;
					$a_yearly = round($yearly - $sub_salary);
					$a_hourly = round($a_yearly / $yearly_hours, 2);
					$a_quarterly = round($a_yearly / 4);
					$a_monthly = round($a_yearly / 12);
					$a_sami_month = round($a_monthly / 2);
					$a_daily = round($a_hourly * $daily_hours, 2);
					$a_week = round($week_hours * $a_hourly);
					$a_bi_week = round($a_week * 2);
				} else {
					$hh = (260 - $total_leaves) / 5;
					$hourly = $a_monthly / (($hh / 12) * $week_hours);
					$yearly = round($hourly * $yearly_hours);
					$quarterly = round($yearly / 4);
					$monthly = round($yearly / 12);
					$sami_month = round($monthly / 2);
					$daily = round($hourly * $daily_hours, 2);
					$week = round($week_hours * $hourly);
					$bi_week = round($week * 2);
				}
			} else {
				if ($request->per == 'Hourly' || $request->per == 'Daily') {
					$a_yearly = $yearly;
					$a_quarterly = $quarterly;
					$a_monthly = $monthly;
					$a_sami_month = $sami_month;
					$a_bi_week = $bi_week;
					$a_week = $week;
					$a_daily = $daily;
					$a_hourly = $hourly;
				} else {
					$yearly = $a_yearly;
					$quarterly = $a_quarterly;
					$monthly = $a_monthly;
					$sami_month = $a_sami_month;
					$bi_week = $a_bi_week;
					$week = $a_week;
					$daily = $a_daily;
					$hourly = $a_hourly;
				}
			}
			if (is_numeric($request->tax)) {
				if ($request->are == 1) {
					$tax = $request->tax / 100;
				} else {
					$tax = 1 - ($request->tax / 100);
				}
			}
			$this->param = array(
				"Hourly" => round($hourly, 2),
				"Daily" => $daily,
				"Week" => $week,
				"Bi_week" => $bi_week,
				"Monthly" => $monthly,
				"Sami_month" => $sami_month,
				"Quarterly" => $quarterly,
				"Yearly" => $yearly,
				"a_Hourly" => round($a_hourly, 2),
				"a_Daily" => $a_daily,
				"a_Week" => $a_week,
				"a_Bi_week" => $a_bi_week,
				"a_Monthly" => $a_monthly,
				"a_Sami_month" => $a_sami_month,
				"a_Quarterly" => $a_quarterly,
				"a_Yearly" => $a_yearly,
				"RESULT" => 1
			);
			if (isset($tax)) {
				$this->param['tax'] = $tax;
			}
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}
	/*************************
		stamp duty Calculator
	 *************************/
	function stamp($request)
	{
		// dd($request->all());
		if ($request->unit_type === 'uk') {
			if (is_numeric($request->value)) {
				$value = $request->value;
				if ($request->uk_method === 'single') {
					if ($value < 125000) {
						$this->param['error'] = "You don't need to pay stamp duty.";
						return $this->param;
					}
					if ($value <= 250000 && $value > 125000) {
						$value = $request->value - 125000;
						$bs = $value;
						$stamp_duty = $value * 0.02;
						$b = $stamp_duty;
					}
					if ($value > 250000) {
						$b = 2500;
						$bs = 125000;
					}
					if ($value <= 925000 && $value > 250000) {
						$value = $request->value - 250000;
						$cs = $value;
						$stamp_duty = ($value * 0.05) + $b;
						$c = ($value * 0.05);
					}
					if ($value > 925000) {
						$c = 33750;
						$cs = 675000;
					}
					if ($value <= 1500000 && $value > 925000) {
						$value = $request->value - 925000;
						$ds = $value;
						$stamp_duty = ($value * 0.10) + $c + $b;
						$d = ($value * 0.10);
					}
					if ($value > 1500000) {
						$d = 57500;
						$ds = 575000;
						$value = $request->value - 1500000;
						$es = $value;
