	/*************************
		stamp duty Calculator
	 *************************/
	function salestax($request)
	{
			// dd($request->all());
		if (is_numeric($request->vat) && is_numeric($request->amount)) {
			$vat = $request->vat;
			$amount = $request->amount;
			$vatAmount = $vat * $amount / 100;
			$netbill = $amount + $vatAmount;
			$method = $request->method;
			if ($method === 'add') {
				$vatAmount = $vat * $amount / 100;
				$netbill = $amount + $vatAmount;
			} else {
				$vat = 1 + ($vat / 100);
				$netbill = round($amount / $vat, 2);
				$vatAmount = $amount - $netbill;
			}
			$this->param['vatAmount'] = round($vatAmount, 2);
			$this->param['netBill'] = round($netbill, 2);
			$this->param['RESULT'] = 1;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill any two fields.';
			return $this->param;
		}
	}
	/*************************
		price elasticity demand Calculator
	 *************************/
	function price($request)
	{
   	// dd($request->all(),'ddddddd');
		if ($request->unit_type === 'Revenue') {

			if (is_numeric($request->i_r) && is_numeric($request->f_r)) {

				if (is_numeric($request->i_r) && is_numeric($request->f_r)) {
					if (is_numeric($request->i_r) && is_numeric($request->f_r) && empty($request->inc)) {
						$i_r = $request->i_r;
						$f_r = $request->f_r;
						if ($i_r == 0) {
							$r_percent = "0";
						} else {
							$r_percent = round(($f_r - $i_r) / $i_r * 100, 2);
						}
						$this->param['i_r'] = $i_r;
						$this->param['f_r'] = $f_r;
						$this->param['r_percent'] = $r_percent;
						$this->param['rev'] = "active";
						$this->param['RESULT'] = 1;
						return $this->param;
					} else {
						$this->param['error'] = 'Please Enter Only Two Values.';
						return $this->param;
					}
				}
				if (is_numeric($request->f_r) && is_numeric($request->inc)) {
					if (empty($request->i_r) && is_numeric($request->f_r) && is_numeric($request->inc)) {
						$inc = ($request->inc / 100) + 1;
						$f_r = $request->f_r;
						$i_r = round($f_r / $inc, 2);
						$this->param['i_r'] = $i_r;
						$this->param['f_r'] = $f_r;
						$this->param['r_percent'] = $request->inc;
						$this->param['rev'] = "active";
						$this->param['RESULT'] = 1;
						return $this->param;
					} else {
						$this->param['error'] = 'Please Enter Only Two Values.';
						return $this->param;
					}
				}
				if (is_numeric($request->i_r) && is_numeric($request->inc)) {
					if (empty($request->f_r) && is_numeric($request->i_r) && is_numeric($request->inc)) {
						$inc = ($request->inc / 100);
						$i_r = $request->i_r;
						$f_r = round($i_r + ($i_r * $inc), 2);
						$this->param['i_r'] = $i_r;
						$this->param['f_r'] = $f_r;
						$this->param['r_percent'] = $request->inc;
						$this->param['rev'] = "active";
						$this->param['RESULT'] = 1;
						return $this->param;
					} else {
						$this->param['error'] = 'Please Enter Only Two Values.';
						return $this->param;
					}
				}
			} else {
				$this->param['error'] = 'Please Enter Only Two Values.';
				return $this->param;
			}
		} elseif ($request->method === '1') {
			if (is_numeric($request->i_p) && is_numeric($request->n_p) && is_numeric($request->i_q) && is_numeric($request->n_q)) {
				$PI = $request->i_p;
				$PN = $request->n_p;
				$QI = $request->i_q;
				$QN = $request->n_q;

				if ($PI == $PN) {
					$PED = (($QN - $QI) / ($QN + $QI) / 2);
				} else {
					$PED = (($QN - $QI) / ($QN + $QI) / 2) / (($PN - $PI) / ($PN + $PI) / 2);
				}

				$PED = round($PED, 4);
				// dd($PED);
				if ($PED > 1) {
					$type = 'Elastic Demand';
				} elseif ($PED == 1) {
					$type = 'Unitary Elastic';
				} elseif ($PED < 1) {
					$type = 'Inelastic Demand';
				} elseif ($PED == 0) {
					$type = 'Perfectly Inelastic';
				} else {
					$type = 'Perfectly Elastic';
				}
				$i_r = $PI * $QI;

				$f_r = $PN * $QN;
				$r_percent = round(($f_r - $i_r) / $i_r * 100, 2);
				$this->param['type'] = $type;
				$this->param['i_r'] = $i_r;
				$this->param['f_r'] = $f_r;
				$this->param['r_percent'] = $r_percent;
				$this->param['PED'] = $PED;
				$this->param['method'] = $request->method;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($request->method === '2') {
			if (is_numeric($request->i_p) && is_numeric($request->n_p) && is_numeric($request->i_q) && is_numeric($request->n_q)) {
				$PI = $request->i_p;
				$PN = $request->n_p;
				$QI = $request->i_q;
				$QN = $request->n_q;
				if ($PI == $PN) {
					$PED = (($QN - $QI) / $QI);
				} else {
					$PED = (($QN - $QI) / $QI) / (($PN - $PI) /  $PI);
				}
				$PED = round($PED, 4);
				if ($PED > 1) {
					$type = 'Elastic Demand';
				} elseif ($PED == 1) {
					$type = 'Unitary Elastic';
				} elseif ($PED < 1) {
					$type = 'Inelastic Demand';
				} elseif ($PED == 0) {
					$type = 'Perfectly Inelastic';
				} else {
					$type = 'Perfectly Elastic';
				}
				$i_r = $PI * $QI;
				$f_r = $PN * $QN;
				$r_percent = round(($f_r - $i_r) / $i_r * 100, 2);
				$this->param['type'] = $type;
				$this->param['i_r'] = $i_r;
				$this->param['f_r'] = $f_r;
				$this->param['r_percent'] = $r_percent;
				$this->param['PED'] = $PED;
				$this->param['method'] = $request->method;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {

				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($request->method === '3') {
			if (is_numeric($request->quantity) && is_numeric($request->prince)) {
				$PED = ($request->quantity / $request->prince);
				$PED = round($PED, 4);
				if ($PED > 1) {
					$type = 'Elastic Demand';
				} elseif ($PED == 1) {
					$type = 'Unitary Elastic';
				} elseif ($PED < 1) {
					$type = 'Inelastic Demand';
				} elseif ($PED == 0) {
					$type = 'Perfectly Inelastic';
				} else {
					$type = 'Perfectly Elastic';
				}
				$this->param['type'] = $type;
				$this->param['PED'] = $PED;
				$this->param['method'] = $request->method;
				$this->param['RESULT'] = 1;
				// dd($this->param);
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
	}
