	/*******************
		Contribution Margin Calculator
	 *******************/
	function contribution($request)
	{
		// dd($request->all());
		$selling_price = $request->selling_price;
		$variable_cost = $request->variable_cost;
		$number_units = $request->number_units;
		$fixed_cost = $request->fixed_cost;

		if (is_numeric($selling_price) && is_numeric($variable_cost) && is_numeric($number_units) && is_numeric($fixed_cost)) {
			$contribution_margin = ($selling_price * $number_units) - ($variable_cost * $number_units);
			$contribution_margin_ratio = $contribution_margin / ($selling_price * $number_units);
			$profit = $contribution_margin - $fixed_cost;

			$this->param['contribution_margin'] = $contribution_margin;
			$this->param['contribution_margin_ratio'] = $contribution_margin_ratio * 100;
			$this->param['profit'] = $profit;
		} else {
			$this->param['error'] = 'Please check your input.';
			return $this->param;
		}

		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/*******************
		Bond Price Calculator
	 *******************/
	function bond($request)
	{
		// dd($request->all());

		$faceValue = trim($request->faceValue);
		$couponRate = trim($request->couponRate);
		$yearsToMaturity = trim($request->yearsToMaturity);
		$frequency = trim($request->frequency);
		$yield = trim($request->yield);

		if (is_numeric($faceValue) && is_numeric($couponRate) && is_numeric($yearsToMaturity) && is_numeric($frequency) && is_numeric($yield)) {
			$couponRate = $couponRate / 100;
			$yield = $yield / 100;
			function calculateBondPrice($faceValue, $couponRate, $yearsToMaturity, $yield)
			{
				$couponPayment = $faceValue * $couponRate;

				$totalPayments = $yearsToMaturity;

				$presentValue = 0;
				for ($i = 1; $i <= $totalPayments; $i++) {
					$presentValue += $couponPayment / (1 + $yield) ** $i;
				}
				$presentValue += $faceValue / (1 + $yield) ** $totalPayments;

				return $presentValue;
			}
			$bondPrice = calculateBondPrice($faceValue, $couponRate, $yearsToMaturity, $yield);
			$couponPayment = $faceValue * $couponRate / $frequency;
			$Annual = $faceValue * $couponRate;
			$this->param['couponPayment'] = round($couponPayment, 2);
			$this->param['annual'] = round($Annual, 2);
			$this->param['bondPrice'] = round($bondPrice, 2);
		} else {
			$this->param['error'] = 'Please check your input.';
			return $this->param;
		}

		$this->param['RESULT'] = 1;
		return $this->param;
	}
