	/*******************
		Rent Increase Calculator
	 *******************/
	function rent($request)
	{
		$rent = trim($request->rent);
		$year = trim($request->year);
		$numbers = trim($request->numbers);
		$numbers_unit = trim($request->numbers_unit);
		if ($numbers_unit === "wks") {
			$numbers = $numbers / 52.143;
		} elseif ($numbers_unit === "mos") {
			$numbers = $numbers / 12;
		} else {
			$numbers = $numbers;
		}
		if (is_numeric($rent) && is_numeric($year) && is_numeric($numbers)) {
			if ($rent == 0) {
				$this->param['error'] = 'Current Annual Rent value cannot be equal to zero.';
				return $this->param;
			}
			if ($year == 0) {
				$this->param['error'] = 'Average Rent Change Per Year value cannot be equal to zero.';
				return $this->param;
			}
			if ($numbers == 0) {
				$this->param['error'] = 'Number Of Years value cannot be equal to zero.';
				return $this->param;
			}
			$years = $year / 100;
			$answer = $rent * pow((1 + $years), $numbers);
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['answer'] = $answer;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
