	/*******************
		GDP Calculator
	 *******************/
	function gdp_cal($request)
	{
		// dd($request->all());
		$consumption = trim($request->consumption);
		$consumption_unit = trim($request->consumption_unit);
		$investment = trim($request->investment);
		$investment_unit = trim($request->investment_unit);
		$purchases = trim($request->purchases);
		$purchases_unit = trim($request->purchases_unit);
		$exports = trim($request->exports);
		$exports_unit = trim($request->exports_unit);
		$imports = trim($request->imports);
		$imports_unit = trim($request->imports_unit);


		function units($consumption, $consumption_unit)
		{
			if ($consumption_unit === "million") {
				$consumption = $consumption * 1;
			} elseif ($consumption_unit === "billion") {
				$consumption = $consumption * 1000;
			} elseif ($consumption_unit === "trillion") {
				$consumption = $consumption * 1000000;
			}
			return $consumption;
		}

		if (is_numeric($consumption) && is_numeric($investment) && is_numeric($purchases) && is_numeric($exports) && is_numeric($imports)) {
			$consumption = units($consumption, $consumption_unit);
			$investment = units($investment, $investment_unit);
			$purchases = units($purchases, $purchases_unit);
			$exports = units($exports, $exports_unit);
			$imports = units($imports, $imports_unit);
			$net_export = $exports - $imports;
			$gdp = $consumption + $investment + $purchases + $net_export;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['net_export'] = $net_export;
		$this->param['gdp'] = $gdp;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/*******************
		GDP per Capita Calculator
	 *******************/
	function gdp($request)
	{
		dd($request->all());
		$real = trim($request->real);
		$real_unit = trim($request->real_unit);
		$population = trim($request->population);
		$population_unit = trim($request->population_unit);

		function capital($real, $real_unit)
		{
			if ($real_unit === "thousand") {
				$real = $real * 1;
			} elseif ($real_unit === "million") {
				$real = $real * 1000;
			} elseif ($real_unit === "billion") {
				$real = $real * 1000000;
			}
			return $real;
		}

		if (is_numeric($real) && is_numeric($population)) {
			$real = capital($real, $real_unit);
			if ($population == 0) {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			} else {
				$population = capital($population, $population_unit);
				$answer = $real / $population;
			}
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['answer'] = $answer;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	/**********************
		Price Calculator
	 **********************/
	function price_cal($request)
	{
		$price = $request->price;
		$gross = $request->gross;
		if (is_numeric($price) && is_numeric($gross)) {
			if ($gross < 0 || $gross > 100) {
				$this->param['error'] = 'Enter Margin 0% to 100%';
				return $this->param;
			}
			$gross = $gross / 100;
			$revenue = $price / (1 - $gross);
			$gross_profit = $revenue * $gross;
			$mark_up = ($gross_profit / $price) * 100;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['revenue'] = round($revenue, 2);
		$this->param['gross_profit'] = round($gross_profit, 2);
		$this->param['mark_up'] = round($mark_up, 2);
		$this->param['RESULT'] = 1;
		return $this->param;
	}
