	/**********************
		Cross Price Elasticity Calculator
	 **********************/
	function cross($request)
	{
		$first = $request->first;
		$second = $request->second;
		$third = $request->third;
		$four = $request->four;

		if (is_numeric($first) && is_numeric($second) && is_numeric($third) && is_numeric($four)) {
			$lamda_a = $first - $third;
			$lamda_b = $second - $four;
			$elasticity = (($first + $third) / ($second + $four)) * ($lamda_b / $lamda_a);
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$this->param['elasticity'] = round($elasticity, 2);
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	/**********************
		Actual Cash Value Calculator
	 **********************/
	function actual($request)
	{
		$price = $request->price;
		$expected = $request->expected;
		$current = $request->current;

		if (is_numeric($price) && is_numeric($expected) && is_numeric($current)) {
			if ($current > $expected) {
				$this->param['error'] = 'Current life of the item cannot be larger than the expected life of the item.';
				return $this->param;
			}
			$acv = $price * ($expected - $current) / $expected;
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$this->param['acv'] = $acv;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	/*******************
		Net Worth Calculator
	 *******************/
	function net($request)
	{
		// dd($request->all());
		$as_real = $request->as_real;
		$as_check = $request->as_check;
		$as_saving = $request->as_saving;
		$as_retire = $request->as_retire;
		$as_car = $request->as_car;
		$as_other = $request->as_other;
		$li_real = $request->li_real;
		$li_card = $request->li_card;
		$li_loan = $request->li_loan;
		$li_stload = $request->li_stload;
		$li_car = $request->li_car;
		$li_other = $request->li_other;

		if (isset($request->submit) || isset($request->res_link)) {
			if (is_numeric($li_real) && is_numeric($li_card) && is_numeric($li_loan) && is_numeric($li_stload) && is_numeric($li_car) && is_numeric($li_other) && is_numeric($as_retire) && is_numeric($as_saving) && is_numeric($as_check) && is_numeric($as_real) && is_numeric($as_car) && is_numeric($as_other)) {
				$assets =	$as_real + $as_check + $as_saving + $as_retire + $as_car + $as_other;
				$liabilities = $li_real + $li_card + $li_loan + $li_stload + $li_car + $li_other;
				$net_worth = $assets - $liabilities;
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
