			$this->param['assets'] = $assets;
			$this->param['liabilities'] = $liabilities;
			$this->param['net_worth'] = $net_worth;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
	}
	/**********************
		Cost Basis Calculator
	 **********************/
	function cost_basis($request)
	{
		$stock = $request->stock;
		$shares = $request->shares;
		$prices = $request->prices;
		foreach ($shares as $key => $share) {
			if (is_numeric($share) && $share !== null && is_numeric($prices[$key]) && $prices[$key] !== null) {
				$shares_values[] = $share;
				$prices_values[] = $prices[$key];
				$upr[] = $shares[$key] * $prices[$key];
			}
		}
		if (isset($shares_values) && isset($prices_values) && count($shares_values) >= 2 && count($prices_values) >= 2) {
			$total_shares = array_sum($shares_values);
			$cost_basis = array_sum($upr) / $total_shares;
			$stock_profit = ($stock - $cost_basis) * $total_shares;
			$percentage = (($stock - $cost_basis) / $cost_basis) * 100;
			$this->param['cost_basis'] = round($cost_basis, 2);
			$this->param['stock_profit'] = round($stock_profit, 2);
			$this->param['percentage'] = round($percentage, 2);
			$this->param['total_shares'] = $total_shares;
			$this->param['shares_values'] = $shares_values;
			$this->param['prices_values'] = $prices_values;
			$this->param['arrayLengthshere'] = count($shares_values) + 1;
			$this->param['arrayLengthprice'] = count($prices_values) + 1;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'At least two stock purchases are required.';
			$this->param['shares'] = $shares;
			$this->param['prices'] = $prices;
			// dd($this->param);
			return $this->param;
		}
	}
