	/**********************
		Monthly Income Calculator
	 **********************/
	function monthly($request)
	{
	// dd($request->all());
		$pay = $request->pay;
		$first = $request->first;
		$second = $request->second;

		if ($pay === "1") {
			if (is_numeric($first) && is_numeric($second)) {
				$annual_income = $first * $second * 52;
				$monthly_income = round($annual_income / 12);
				$sami_monthly_income = round($monthly_income / 2, 2);
				$daily_income = $first * 8;
				$weekly_income = $first * $second;
				$bi_weekly_income = round($weekly_income * 2);
				$hourly_income = $first;
				$quarterly_income = round($annual_income / 4, 2);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else if ($pay === "2") {
			if (is_numeric($first) && is_numeric($second)) {
				$daily_income = $first;
				$weekly_income = $first * $second;
				$hourly_income = round($first / 8, 2);
				$annual_income = $hourly_income * 40 * 52;
				$monthly_income = round($annual_income / 12);
				$sami_monthly_income = round($monthly_income / 2, 2);
				$bi_weekly_income = round($weekly_income * 2);
				$quarterly_income = round($annual_income / 4, 2);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else if ($pay === "3") {
			if (is_numeric($first)) {
				$daily_income = round($first / 5, 2);
				$weekly_income = $first;
				$hourly_income = round($first / 40, 2);
				$annual_income = $hourly_income * 40 * 52;
				$monthly_income = round($annual_income / 12, 2);
				$sami_monthly_income = round($monthly_income / 2, 2);
				$bi_weekly_income = round($weekly_income * 2);
				$quarterly_income = round($annual_income / 4, 2);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else if ($pay === "4") {
			if (is_numeric($first)) {
				$weekly_income = round($first / 2, 2);
				$daily_income = round($weekly_income / 5, 2);
				$hourly_income = round($daily_income / 8, 2);
				$annual_income = $hourly_income * 40 * 52;
				$monthly_income = round($annual_income / 12, 2);
				$sami_monthly_income = round($monthly_income / 2, 2);
				$bi_weekly_income = $first;
				$quarterly_income = round($annual_income / 4, 2);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else if ($pay === "5") {
			if (is_numeric($first)) {
				$sami_monthly_income = $first;
				$monthly_income = round($sami_monthly_income * 2);
				$annual_income = $monthly_income * 12;
				$weekly_income = round($annual_income / 52, 2);
				$daily_income = round($weekly_income / 5, 2);
				$hourly_income = round($daily_income / 8, 2);
				$bi_weekly_income = $weekly_income * 2;
				$quarterly_income = round($annual_income / 4, 2);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else if ($pay === "6") {
			if (is_numeric($first)) {
				$quarterly_income = $first;
				$annual_income = $first * 4;
				$weekly_income = round($annual_income / 52, 2);
				$monthly_income = round($annual_income / 12, 2);
				$sami_monthly_income = round($monthly_income / 2, 2);
				$daily_income = round($weekly_income / 5, 2);
				$hourly_income = round($daily_income / 8, 2);
				$bi_weekly_income = $weekly_income * 2;
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else {
			if (is_numeric($first)) {
				$weekly_income = round($first / 52, 2);
				$daily_income = round($weekly_income / 5, 2);
				$hourly_income = round($daily_income / 8, 2);
				$annual_income = $first;
				$monthly_income = round($annual_income / 12, 2);
				$bi_weekly_income = $weekly_income * 2;
				$sami_monthly_income = round($monthly_income / 2, 2);
				$quarterly_income = round($annual_income / 4, 2);
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		$this->param['hourly_income'] = $hourly_income;
		$this->param['daily_income'] = $daily_income;
		$this->param['weekly_income'] = $weekly_income;
		$this->param['bi_weekly_income'] = $bi_weekly_income;
		$this->param['sami_monthly_income'] = $sami_monthly_income;
		$this->param['monthly_income'] = $monthly_income;
		$this->param['quarterly_income'] = $quarterly_income;
		$this->param['annual_income'] = $annual_income;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/*******************
   		Deadweight Loss Calculator
	 *******************/
	function deadweight($request)
	{
		$original_price = $request->original_price;
		$new_price = $request->new_price;
		$original_quantity = $request->original_quantity;
		$new_quantity = $request->new_quantity;

		if (is_numeric($original_price) && is_numeric($new_price) && is_numeric($original_quantity) && is_numeric($new_quantity)) {
			$total_price = ($new_price - $original_price);
			$total_quantity = ($original_quantity - $new_quantity);
			$dead = $total_price * $total_quantity;
			$deadweight = $dead / 2;
			$this->param['deadweight'] = $deadweight;
			$this->param['dead'] = $dead;
			$this->param['total_price'] = $total_price;
			$this->param['total_quantity'] = $total_quantity;
		} else {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}
