	/**********************
		Beta Calculator
	 **********************/

	function beta($request)
	{
		$rs = $request->rs;
		$rm = $request->rm;

		function sigFig($value, $digits)
		{
			if ($value !== '') {
				if ($value === 0) {
					$decimalPlaces = $digits - 1;
				} elseif ($value < 0) {
					$decimalPlaces = $digits - floor(log10($value * -1)) - 1;
				} else {
					$decimalPlaces = $digits - floor(log10($value)) - 1;
				}
				$answer = round($value, $decimalPlaces);
				return $answer;
			}
		}

		if (empty($rs) && empty($rm)) {
			$this->param['error'] = 'Please! Check Your Input.';
			return $this->param;
		}

		$rs = array_map('trim', array_filter(explode(',', $rs)));
		$rm = array_map('trim', array_filter(explode(',', $rm)));
		$n = count($rs);
		$check = true;
		if ($n !== count($rm)) {
			$this->param['error'] = 'The number of values should be same in both inputs.';
			return $this->param;
		}
		foreach ($rs as $key => $value) {
			if (!is_numeric($value)) {
				$check = false;
			}
			if (!is_numeric($rm[$key])) {
				$check = false;
			}
		}
		if ($check === true) {
			$xy_sum = 0;
			$xi2 = [];
			$yi2 = [];
			foreach ($rm as $key => $xi) {
				$xi2[] = pow($xi, 2);
				$yi = $rs[$key];
				$yi2[] = pow($yi, 2);
				$xy_sum += $xi * $yi;
			}
			$rs_sum = array_sum($rs);
			$rm_sum = array_sum($rm);
			$xi2_sum = array_sum($xi2);
			$yi2_sum = array_sum($yi2);

			$ss_xx = $xi2_sum - (pow($rm_sum, 2) / $n);
			$ss_yy = $yi2_sum - (pow($rs_sum, 2) / $n);
			$ss_xy = $xy_sum - (($rm_sum * $rs_sum) / $n);
			$beta_1 = $ss_xy / $ss_xx;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}

		$this->param['n'] = $n;
		$this->param['rs'] = $rs;
		$this->param['rm'] = $rm;
		$this->param['rs_sum'] = $rs_sum;
		$this->param['rm_sum'] = $rm_sum;
		$this->param['xi2'] = $xi2;
		$this->param['yi2'] = $yi2;
		$this->param['xi2_sum'] = $xi2_sum;
		$this->param['yi2_sum'] = $yi2_sum;
		$this->param['xy_sum'] = $xy_sum;
		$this->param['ss_xx'] = $ss_xx;
		$this->param['ss_yy'] = $ss_yy;
		$this->param['ss_xy'] = $ss_xy;
		$this->param['beta_1'] = sigFig($beta_1, 4);
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/*******************
		Earnings Per Share Calculator
	 *******************/
	function earnings($request)
	{
		$net_income = trim($request->net_income);
		$dividends = trim($request->dividends);
		$common_shares = trim($request->common_shares);

		if (is_numeric($net_income) && is_numeric($dividends) && is_numeric($common_shares)) {
			if ($common_shares <= 0) {
				$this->param['error'] = 'Number of common shares should be an integer greater than 0.';
				return $this->param;
			}
			$share_income = $net_income - $dividends;
			$share_dividends = $share_income / $common_shares;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['share_dividends'] = $share_dividends;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	/**********************
		Growth Rate Calculator
	 **********************/
	function growth($request)
	{
		// dd($request->all());
		$operation = trim($request->operation);
		$present_val = trim($request->present_val);
		$past_val = trim($request->past_val);
		$time_val = trim($request->time_val);
		if ($operation == "1") {
			if (is_numeric($present_val) && is_numeric($past_val)) {
				$growth_diff = $present_val - $past_val;
				$growth_val	= $growth_diff / $past_val;
				$growth_percent = $growth_val * 100;
				$this->param['growth_diff'] = $growth_diff;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				$this->param['operation'] = $operation;
				return $this->param;
			}
		} else if ($operation == "2") {
			if (is_numeric($present_val) && is_numeric($past_val) && is_numeric($time_val)) {
				$growth_sub = $present_val / $past_val;
				$time_p = 1 / $time_val;
				$g_val = pow($growth_sub, $time_p);
				$growth_val = $g_val - 1;
				$growth_percent = $growth_val * 100;
				$this->param['growth_sub'] = $growth_sub;
				$this->param['g_val'] = $g_val;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				$this->param['operation'] = $operation;
				return $this->param;
			}
		}
		$this->param['present_val'] = $present_val;
		$this->param['past_val'] = $past_val;
		$this->param['time_val'] = $time_val;
		$this->param['growth_val'] = $growth_val;
		$this->param['growth_percent'] = $growth_percent;
		$this->param['operation'] = $operation;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/**********************
		Time and a Half Calculator
	 **********************/
	function time_and_half($request)
	{
		$currency = trim($request->currency);
		$normal_pay = trim($request->normal_pay);
		$normal_time = trim($request->normal_time);
		$over_time = trim($request->over_time);
		$multiplier = trim($request->multiplier);
		$pay_period = trim($request->pay_period);

		if (is_numeric($normal_pay) && is_numeric($normal_time) && is_numeric($over_time) && is_numeric($pay_period)) {
			if ($normal_pay >= 0 && $normal_time >= 0 && $over_time >= 0 && $pay_period >= 0) {
				if (($over_time == "" && $normal_pay == "") || ($over_time == 0 && $normal_pay == 0)) {
					$half_pay =  '';
					$half = '';
					$Overtime_Pay_per_Year = 0;
					$normal_pay = 0;
					$normal_time = 0;
				} else if (($over_time == "") || ($over_time == 0)) {
					$half = $normal_pay * $multiplier;
					$half_pay = 0;
					$Overtime_Pay_per_Year = 0;
				} else if ($normal_pay == "" && $normal_time == "" || $normal_pay == 0 && $normal_time == 0) {
					$this->param['error'] = 'Please Enter Your Pay';
					return $this->param;
				} else {
					$half = $normal_pay * $multiplier;
					$half_pay = $normal_pay * $multiplier * $over_time;
					$Overtime_Pay_per_Year = $half_pay * $pay_period;
				}

				if ($normal_pay == "" && $normal_time == "" || $normal_pay == 0 && $normal_time == 0) {
					$standered_pay = $normal_pay;
					$total = "";
					$Regular_Pay_per_Year = 0;
					$Total_Pay_per_Year = 0;
				} else {
					$standered_pay = $normal_pay * $normal_time;
					$total = $standered_pay + $half_pay;
					$Regular_Pay_per_Year = $standered_pay * $pay_period;
					$Total_Pay_per_Year = $total * $pay_period;
				}
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
			$this->param['currency']   				= $currency;
			$this->param['normal_pay']   			= $normal_pay;
			$this->param['half']   					= $half;
			$this->param['half_pay'] 				= $half_pay;
			$this->param['Overtime_Pay_per_Year']  	= $Overtime_Pay_per_Year;
			$this->param['standered_pay']   		= $standered_pay;
			$this->param['total']   				= $total;
			$this->param['Regular_Pay_per_Year']  	= $Regular_Pay_per_Year;
			$this->param['Total_Pay_per_Year']   	= $Total_Pay_per_Year;
			$this->param['multiplier']   	= $multiplier;
			$this->param['over_time']   	= $over_time;
			$this->param['normal_time']   	= $normal_time;
			$this->param['RESULT'] 	    = 1;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
	}

	/**********************
		Option Profits Calculator
	 **********************/
	function options($reequest)
	{

		$ot     = trim($reequest->ot);
		$sp  	= trim($reequest->sp);
		$op     = trim($reequest->op);
		$stp    = trim($reequest->stp);
		$nc     = trim($reequest->nc);

		if (!empty($ot) && is_numeric($sp) && is_numeric($op) && is_numeric($stp) && is_numeric($nc)) {
			if ($sp >= 0 && $op >= 0 && $stp >= 0 && $nc >= 0) {
				if ($ot == 'c') {
					$ec = $nc * 100;
					$ans = ($sp - $stp - $op) * $ec;
				} elseif ($ot == 'p') {
					$ec = $nc * 100;
					$ans = ($stp - ($sp + $op)) * $ec;
				}
			} else {

				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
			$this->param['sp']   		= $sp;
			$this->param['nc']   		= $nc;
			$this->param['stp']   		= $stp;
			$this->param['op']   		= $op;
			$this->param['ot']   		= $ot;
			$this->param['ec']   		= $ec;
			$this->param['ans']   		= $ans;
			$this->param['RESULT'] 	    = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
	}

	/**********************
		Dividend Yield Calculator
	 **********************/
	function dividend($request)
	{
		$first = $request->first;
		$operations = $request->operations;
		$second = $request->second;

		if (is_numeric($first) && is_numeric($second)) {
			if ($first >= 0) {
				if ($second >= 0) {
					if ($operations == "1") {
						$annual_div = $first;
					} elseif ($operations == "2") {
						$annual_div = $first * 2;
					} elseif ($operations == "3") {
						$annual_div = $first * 4;
					} elseif ($operations == "4") {
						$annual_div = $first * 12;
					}
					$divide = $annual_div / $second;
					$dividend_yield = $divide * 100;
				} else {
					$this->param['error'] = 'Share price should not be negative.';
					return $this->param;
				}
			} else {
				$this->param['error'] = 'Dividends per period should not be negative.';
				return $this->param;
			}
		} else {

			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['annual_div'] = $annual_div;
		$this->param['dividend_yield'] = $dividend_yield;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	/**********************
		Dividend Yield Calculator
	 **********************/
	function markdown($request)
	{
		$osp = $request->osp;
		$asp = $request->asp;

		if (is_numeric($osp) && is_numeric($asp) && $osp > 0 && $asp > 0) {
			if ($asp < $osp) {
				$markdown = $osp - $asp;
				$markdown_percent = ($markdown / $asp) * 100;
				$this->param['markdown'] = $markdown;
				$this->param['markdown_percent'] = round($markdown_percent, 2);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Original Selling Price > Actual Selling Price';
				return $this->param;
			}
		} else {

			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
	}
	/**********************
		AGI Caluclator
	 **********************/
	function agi($request)
	{
		$input1 = $request->input1;
		$input2 = $request->input2;
		$input3 = $request->input3;
		$input4 = $request->input4;
		$input5 = $request->input5;
		$input6 = $request->input6;
		$input7 = $request->input7;
		$input8 = $request->input8;
		$input9 = $request->input9;
		$input10 = $request->input10;
		$input11 = $request->input11;
		$input12 = $request->input12;
		$input13 = $request->input13;
		$input14 = $request->input14;
		$input15 = $request->input15;
		$input16 = $request->input16;
		$input17 = $request->input17;
		$input18 = $request->input18;
		$input19 = $request->input19;
		$input20 = $request->input20;
		$input21 = $request->input21;
		$input22 = $request->input22;
		$input23 = $request->input23;
		$input24 = $request->input24;

		if (is_numeric($input1) && is_numeric($input2) && is_numeric($input3) && is_numeric($input4) && is_numeric($input5) && is_numeric($input6) && is_numeric($input7) && is_numeric($input8) && is_numeric($input9) && is_numeric($input10) && is_numeric($input11) && is_numeric($input12) && is_numeric($input13) && is_numeric($input14) && is_numeric($input15) && is_numeric($input16) && is_numeric($input17) && is_numeric($input18) && is_numeric($input19) && is_numeric($input20) && is_numeric($input21) && is_numeric($input22) && is_numeric($input23) && is_numeric($input24)) {
			$add1 = $input1 + $input2 + $input3 + $input4 + $input5 + $input6 + $input7 + $input8 + $input9 + $input10 + $input11 + $input12 + $input13;
			$add2 = $input14 + $input15 + $input16 + $input17 + $input18 + $input19 + $input20 + $input21 + $input22 + $input23 + $input24;
			$minus = $add1 - $add2;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['add1'] = $add1;
		$this->param['add2'] = $add2;
		$this->param['minus'] = $minus;
		$this->param['RESULT'] = 1;
		return $this->param;
	}
	/**********************
		AGI Caluclator
	 **********************/
	// mpc Caluclator  
	function mpc($request)
	{
		$this->param = []; // Initialize $this->param

		$income = $request->income;
		$save = $request->save;

		try {
			if ($this->setVeri($income, $save)) {
				$ans = $this->getAns();
				$this->param['ans'] = $ans;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		} catch (Exception $e) {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
	}

	private function setVeri($in, $sv)
	{
		if (is_numeric($in) && is_numeric($sv)) {
			$this->income = $in;
			$this->save = $sv;
			return true;
		} else {
			return false;
		}
	}

	private function getAns()
	{
		if (!$this->income) {
			throw new Exception('Division by zero.');
		} else {
			return ($this->save / $this->income);
		}
	}

	/**********************
		Future Value of Annuity Caluclator
	 **********************/
	function future($request)
	{
		// dd($request->all());
		$payment = $request->payment;
		$interest = $request->interest;
		$term = $request->term;
		$term_unit = $request->term_unit;
		$compounding = $request->compounding;
		$payment_fre = $request->payment_fre;
		$annuity_type = $request->annuity_type;
		$g = $request->g;

		if (is_numeric($payment) && is_numeric($interest) && is_numeric($term)) {
			$term = $this->yearsConvert($term, $term_unit);
			$r = $interest / 100;
			$i = $r / $compounding;
			$n = $term * $compounding;
			$f_part = 1 + $i;
			$s_part = pow($f_part, $n);
			$up_part = $s_part - 1;
			$l_part = $payment / $i;
			if ($annuity_type == "mons") {
				$annuity = $up_part * $l_part;
			} else if ($annuity_type == "yrs") {
				$annuity_ans = $up_part * $l_part;
				$annuity = $annuity_ans * $f_part;
			}
			if (is_numeric($g)) {
				if ($g == $i) {
					$n1 = $n - 1;
					$s_part2 = pow($f_part, $n1);
					$annuity = $payment * $n * $s_part2;
				} else if ($g != $i) {
					$G = $g / 100;
					$ig = $i - $G;
					$iG = 1 + $G;
					$ig_part = pow($iG, $n);
					$part1 = $payment / $ig;
					$part2 = $s_part - $ig_part;
					$annuity = $part1 * $part2;
				}
			}
			if ($compounding == "366") {
				$ry = $r * $term;
				$e1 = pow(2.718, $ry);
				$e2 = pow(2.718, $r);
				$top = $e1 - 1;
				$down = $e2 - 1;
				$annu = $top / $down;
				$annuity = $payment * $annu;
			}
			$div = $r / $compounding;
			$top_div = $compounding / $payment_fre;
			$final_a = $div + 1;
			$overall = pow($final_a, $top_div);
			$res = $overall - 1;
			$equ = $payment_fre * $res;
			$equ = $equ * 100;
			$equ2 = $equ;
			if ($payment_fre == "1") {
				$term = $term * 1;
				$annuity = $annuity * 1;
				$equ2 = $equ;
			} else if ($payment_fre == "2") {
				$term = $term * 2;
				$annuity = $annuity * 2;
				$equ2 = $equ / 2;
			} else if ($payment_fre == "4") {
				$term = $term * 4;
				$annuity = $annuity * 4;
				$equ2 = $equ / 4;
			} else if ($payment_fre == "12") {
				$term = $term * 12;
				$annuity = $annuity * 12;
				$equ2 = $equ / 12;
			} else if ($payment_fre == "52") {
				$term = $term * 52;
				$annuity = $annuity * 52;
				$equ2 = $equ / 52;
			} else if ($payment_fre == "365") {
				$term = $term * 365;
				$annuity = $annuity * 365;
				$equ2 = $equ / 365;
			}
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$annuity = number_format($annuity, 2);
		$term = number_format($term, 2);
		$equ = number_format($equ, 4);
		$equ2 = number_format($equ2, 4);
		$this->param['term'] = $term;
		$this->param['annuity'] = $annuity;
		$this->param['equ'] = $equ;
		$this->param['equ2'] = $equ2;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	private function yearsConvert($term, $term_unit)
	{

		if ($term_unit = "mons") {
			return $term / 12;
		} elseif ($term_unit = "yrs") {
			return $term * 1;
		}
		return $term;
	}
	/**********************
		 maximum Profit Calculator 
	 **********************/

	function maximum($request)
	{
		$p = $request->p;
		$Q = $request->Q;
		$C = $request->C;
		if (is_numeric($p) && is_numeric($Q) && is_numeric($C)) {
			$R = $p * $Q;
			$cost = $C * $p;
			$profit = $R - $cost;
			$this->param['R'] = $R;
			$this->param['profit'] = $profit;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
	}

	/**********************
		Cap Rate Calculator
	 **********************/
	function cap($request)
	{
		// dd($request->all());

		$prop_val = $request->prop_val;
		$ann_grs_inc = $request->ann_grs_inc;
		$op_exp = $request->op_exp;
		$op_exp_unit = $request->op_exp_unit;
		$vac_rate = $request->vac_rate;

		$prop_val = str_replace(',', '', $prop_val);
		$ann_grs_inc = str_replace(',', '', $ann_grs_inc);
		$op_exp = str_replace(',', '', $op_exp);
		$vac_rate = str_replace(',', '', $vac_rate);
		if (is_numeric($prop_val) && is_numeric($ann_grs_inc) && is_numeric($op_exp)) {
			if (is_numeric($vac_rate)) {
				$vac_rate = $vac_rate;
			} else {
				$vac_rate = '0';
			}
			$vac_rate1 = ($vac_rate / 100) * $ann_grs_inc;
			$grs_op_inc = $ann_grs_inc - $vac_rate1;
			if ($op_exp_unit === '%') {
				$ann_net_inc = ((100 - $op_exp) / 100) * ((100 - $vac_rate) / 100) * $ann_grs_inc;
				$this->param['percent'] = "%";
			} else {
				$ann_net_inc = $grs_op_inc - $op_exp;
			}
			$cap = ($ann_net_inc / $prop_val) * 100;
			$this->param['grs_op_inc'] = number_format($grs_op_inc);
			$this->param['ann_net_inc'] = number_format($ann_net_inc);
			$this->param['cap'] = round($cap, 3);
			$this->param['prop_val'] = number_format($prop_val);
			$this->param['ann_grs_inc'] = number_format($ann_grs_inc);
			$this->param['op_exp'] = number_format($op_exp);
			$this->param['vac_rate'] = number_format($vac_rate);
			$this->param['vac_rate1'] = number_format($vac_rate1);
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
	}
	/**********************
		income Elasticity of Demand Calculator/
	 **********************/
	function income($request)
	{
		if (is_numeric($request->i_p) && is_numeric($request->n_p) && is_numeric($request->i_q) && is_numeric($request->n_q)) {
			$ip = $request->i_p;
			$np = $request->n_p;
			$iq = $request->i_q;
			$nq = $request->n_q;
			$pi = ($nq - $iq) / $iq;
			$pq = ($np - $ip) / $ip;
			$eq = ($nq - $iq) / ($nq + $iq);
			$ep = ($np - $ip) / ($np + $ip);
			$ie = $eq / $ep;
			$ir = $ip * $iq;
			$fr = $np * $nq;
			$R = round(($ip * $iq) - ($np * $nq), 2);
			if ($R > 0) {
				$rs = 'Elastic Demand';
			} elseif ($R == 1) {
				$rs = 'Unitary Elastic';
			} elseif ($R < 1) {
				$rs = 'Inelastic Demand';
			} elseif ($R == 0) {
				$rs = 'Perfectly Inelastic';
			} else {
				$rs = 'Perfectly Elastic';
			}
			$rin = round(($fr - $ir) / $ir * 100, 2);
			$cq = round($pi, 2);
			$cp = round($pq, 2);
			$this->param['ie'] = $ie;
			$this->param['ir'] = $ir;
			$this->param['fr'] = $fr;
			$this->param['sr'] = $rs;
			$this->param['cq'] = $cq;
			$this->param['cp'] = $cp;
			$this->param['rin'] = $rin;
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}

