	/**********************
	 Margin  Calculator/
	 **********************/

	function margin($request)
	{
		// dd($request->all());
		if ($request->per && $request->x && $request->y && $request->z) {
			$z = explode('@', $request->per);
			$z = $z[0];
			$p = $request->x / 100;
			$n = $request->y;
			if ($z == 11 || $z == 22) {
				$z = 2.05;
			}
			$ans = round(($z * sqrt($p * (1 - $p)) / sqrt($n)) * 100, 4);

			if (!empty($request->z)) {
				$Na = $request->z;
				// if ($n>$Nmycurrancya) {
				// 	$this->param['error'] = 'Population size must be greater than Simple size.';
				// 	return $this->param;
				// }
				if ($n === $Na) {
					$ans = 0;
				} else {
					$ans = round(($z * sqrt($p * (1 - $p)) / sqrt(($Na - 1) * $n / ($Na - $n))) * 100, 4);
				}
			}
			$this->param['ans'] = "±" . $ans . "%";
			$this->param['RESULT'] = 1;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}
