	/**********************
		Macrs Calculator/
	 **********************/
	function macrs($request)
	{
	// dd($request->all());
		if (is_numeric($request->basic) && is_numeric($request->percent) && $request->date) {

			$dates = DateTime::createFromFormat('Y-m-d', $request->date);
			$date = $dates->format('M,d,Y');
			$mycurrancy = $request->mycurrancy;
			$total_years = '';
			$total_ev = '';
			$date = explode(',', $date);
			$year = $date[2];
			$mon = $date[0];
			$basic = (($request->percent / 100) * $request->basic);
			$original = $basic;
			$this->param['original'] = $original;
			if ($request->method == 'dbl') {
				if (empty($request->sal)) {
					$this->param['error'] = 'Please fill all fields.';
					return $this->param;
				}

				$basic = $request->basic;
				$original = $basic;
				$salvage = $request->sal;
				$years = $request->period;
				$output = "";
				$sum = 0;
				$method = "DDB";
				$rate = round((($basic / $years) / $basic) * 2 * 100, 2);
				for ($i = 1; $i <= $years; $i++) {
					$dep = (($rate / 100) * $basic);
					$sum = $sum + $dep;
					$b_v = $original - $sum;
					if ($b_v < $salvage) {
						$b_v = $salvage;
						$dep = $basic - $b_v;
						$rate = round(($dep / $basic) * 100, 2);
						$years = $i;
					}
					$mycurrancy = $request->mycurrancy;
					if ($request->round == 'yes') {
						$output .= "<tr>
				            <td class='py-2 border-b'>" . ($year) . "</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($basic) . "</td>
				            <td class='py-2 border-b'>" . ($rate) . "%</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($dep) . "</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($sum) . "</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($b_v) . "</td>
				            <td class='py-2 border-b'>" . $method . "</td>
				          </tr>";
					} else {
						$output .= "<tr>
				            <td class='py-2 border-b'>" . ($year) . "</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($basic, 2) . "</td>
				            <td class='py-2 border-b'>" . ($rate) . "%</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($dep, 2) . "</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($sum, 2) . "</td>
				            <td class='py-2 border-b'>" . $mycurrancy . round($b_v, 2) . "</td>
				            <td class='py-2 border-b'>" . $method . "</td>
				          </tr>";
					}
					$year = $year + 1;
					$basic = $b_v;
				}
				$this->param['output'] = $output;
				$this->param['RESULT'] = 1;
				return $this->param;
			}
			if (empty($request->percent)) {
				$this->session->set_flashdata('macrs', "Please fill all fields.");
				return $this->param;
			}
			if ($request->method == 'asl') {
				$saal = $request->ads_;
				$sal_check = explode('.', $saal);
				if (count($sal_check) == 1) {
					if ($request->conver == '2') {
						$output = "";
						$sum = 0;
						$method = "ADS SL";
						$saal_ = $saal + 1;
						for ($i = 1; $i <= $saal_; $i++) {
							if ($i == 1) {
								$rate = (100 / $saal) / 2;
							}
							if ($i != 1) {
								$rate = 100 / $saal;
							}
							if ($i == $saal_) {
								$rate = (100 / $saal) / 2;
