	/**********************
		Macrs Calculator/
	 **********************/
	function profit($request)
	{

		if (is_numeric($request->x) && is_numeric($request->y)) {
			if ($request->method === "Gross") {
				$margin = round(100 * ($request->y - $request->x) / $request->y, 2);
				$profit = $request->y - $request->x;
				$mark = round(($profit / $request->x) * 100, 2);
				$this->param['margin'] = $margin . " %";
				$this->param['profit'] = $request->hidden_currency . ' ' . $profit;
				$this->param['mark'] = $mark . " %";
				$this->param['RESULT'] = 1;

				return $this->param;
			}
			if ($request->method === "Net") {
				$margin = round(($request->y / $request->x) * 100, 2);
				$this->param['margin'] = @$margin . " %";
				$this->param['RESULT'] = 1;
				return $this->param;
			}
			if ($request->method === "Operating") {
				$margin = round(($request->y / $request->x) * 100, 2);
				$this->param['operating'] = @$margin . " %";
				$this->param['RESULT'] = 1;
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}
	/**********************
		CPM Calculator/
	 **********************/
	function cpm($request)
	{
		$currency = $request->my_current;
		if (isset($request->checkbox)) {
			if (is_numeric($request->xf) && is_numeric($request->yf) && is_numeric($request->xs) && is_numeric($request->ys)) {
				if ($request->methodf === 'cpm') {
					$ansf = round((1000 * $request->yf) / $request->xf, 3);
					$cpmf = $ansf;
					$ansf = $currency . ' ' . $ansf;
				} elseif ($request->methodf === 'tc') {
					$ansf = round(($request->xf * $request->yf) / 1000, 3);
					$cpmf = $request->xf;
					$ansf = $currency . ' ' . $ansf;
				} else {
					$cpmf = $request->xf;
					$ansf = round((1000 * $request->yf) / $request->xf, 3);
				}
				if ($request->methods === 'cpm') {
					$anss = round((1000 * $request->ys) / $request->xs, 3);
					$cpms = $anss;
					$anss = $currency . ' ' . $anss;
				} elseif ($request->methods === 'tc') {
					$anss = round(($request->xs * $request->ys) / 1000, 3);
					$cpms = $request->xs;
					$anss = $currency . ' ' . $anss;
				} else {
					$cpms = $request->xs;
					$anss = round((1000 * $request->ys) / $request->xs, 3);
				}
				$this->param['ansf'] = $ansf;
				$this->param['cpmf'] = $cpmf;
				$this->param['anss'] = $anss;
				$this->param['cpms'] = $cpms;
				$this->param['methodf'] = $request->methodf;
				$this->param['methods'] = $request->methods;
				$this->param['RESULT'] = 1;
				// dd($this->param);
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else {

			if (is_numeric($request->x) && is_numeric($request->y)) {

				if ($request->method === 'cpm') {
					if ($request->x == '0') {
						$ans = '0';
					} else {
						$ans = round((1000 * $request->y) / $request->x, 3);
					}

					$this->param['ans'] = $currency . ' ' . $ans;
					$this->param['RESULT'] = 1;
					$this->param['method'] = $request->method;
					return $this->param;
				} elseif ($request->method === 'tc') {
					if ($request->x == '0') {
						$ans = '0';
					} else {
						$ans = round(($request->x * $request->y) / 1000, 3);
					}
					$this->param['ans'] = $currency . ' ' . $ans;
					$this->param['RESULT'] = 1;
					$this->param['method'] = $request->method;
					return $this->param;
				} else {
					if ($request->x == '0') {
						$ans = '0';
					} else {
						$ans = round((1000 * $request->y) / $request->x, 3);
					}
					$this->param['ans'] = $ans;
					$this->param['RESULT'] = 1;
					$this->param['method'] = $request->method;
					return $this->param;
				}
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
	}
	/**********************
		Markup Calculator/
	 **********************/
	function markup($request)
	{
		// dd($request->all());
		if ($request->to_cal === '1') {
			if (is_numeric($request->a) && is_numeric($request->b)) {
				$cost = $request->a;
				$markup = $request->b;
				$revenue = $cost + ($cost * ($markup / 100));
				$profit = $revenue - $cost;
				$margin = (100 * $profit / $revenue);
				$this->param['cost'] = number_format($cost, 2);
				$this->param['markup'] = number_format($markup, 2);
				$this->param['revenue'] = number_format($revenue, 2);
				$this->param['profit'] = number_format($profit, 2);
				$this->param['margin'] = number_format($margin, 2);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($request->to_cal === '2') {
			if (is_numeric($request->a) && is_numeric($request->c)) {
				$cost = $request->a;
				$revenue = $request->c;
				$profit = $revenue - $cost;
				$margin = (100 * $profit / $revenue);
				$markup = 100 * $profit / $cost;
				$this->param['cost'] = number_format($cost, 2);
				$this->param['markup'] = number_format($markup, 2);
				$this->param['revenue'] = number_format($revenue, 2);
				$this->param['profit'] = number_format($profit, 2);
				$this->param['margin'] = number_format($margin, 2);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($request->to_cal === '3') {
			if (is_numeric($request->a) && is_numeric($request->d)) {
				$cost = $request->a;
				$profit = $request->d;
				$revenue = $profit + $cost;
				$margin = (100 * $profit / $revenue);
				$markup = 100 * $profit / $cost;
				$this->param['cost'] = number_format($cost, 2);
				$this->param['markup'] = number_format($markup, 2);
				$this->param['revenue'] = number_format($revenue, 2);
				$this->param['profit'] = number_format($profit, 2);
				$this->param['margin'] = number_format($margin, 2);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($request->to_cal === '4') {
			if (is_numeric($request->b) && is_numeric($request->c)) {
				$markup = $request->b;
				$revenue = $request->c;
				$margin = (($markup / 100) / (1 + ($markup / 100))) * 100;
				$cost = $revenue - ($margin * $revenue / 100);
				$profit = $revenue - $cost;
				$this->param['cost'] = number_format($cost, 2);
				$this->param['markup'] = number_format($markup, 2);
				$this->param['revenue'] = number_format($revenue, 2);
				$this->param['profit'] = number_format($profit, 2);
				$this->param['margin'] = number_format($margin, 2);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($request->to_cal === '5') {
			if (is_numeric($request->b) && is_numeric($request->d)) {
				$markup = $request->b;
				$profit = $request->d;
				$margin = (($markup / 100) / (1 + ($markup / 100))) * 100;
				$revenue = 100 * $profit / $margin;
				$cost = $revenue - ($margin * $revenue / 100);
				$this->param['cost'] = number_format($cost, 2);
				$this->param['markup'] = number_format($markup, 2);
				$this->param['revenue'] = number_format($revenue, 2);
				$this->param['profit'] = number_format($profit, 2);
				$this->param['margin'] = number_format($margin, 2);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($request->to_cal === '6') {
			if (is_numeric($request->c) && is_numeric($request->d)) {
				$revenue = $request->c;
				$profit = $request->d;
				$cost = $revenue - $profit;
				$markup = 100 * $profit / $cost;
				$margin = (($markup / 100) / (1 + ($markup / 100))) * 100;
				$this->param['cost'] = number_format($cost, 2);
				$this->param['markup'] = number_format($markup, 2);
				$this->param['revenue'] = number_format($revenue, 2);
				$this->param['profit'] = number_format($profit, 2);
				$this->param['margin'] = number_format($margin, 2);
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}
	/**********************
		CAPM Calculator/
	 **********************/
	function capm($request)
	{
		// dd($request->all());
		$cal = $request->cal;
		$rf = $request->rf;
		$rm = $request->rm;
		$bi = $request->bi;
		$r = $request->r;

		if ($request->cal && is_numeric($request->rf) && is_numeric($request->rm) && is_numeric($request->bi) && is_numeric($request->r)) {

			if ($cal === 'R' && is_numeric($rf) && is_numeric($rm) && is_numeric($bi)) {
				$eq_market_prem = $rm - $rf;
				$risk_prem = $bi * $eq_market_prem;
				$r = $rf + $risk_prem;
				$r_mr = ($rm * $bi) / $rf;
				$r_mrp = $r + $r_mr;
			} elseif ($cal === 'Bi' && is_numeric($r) && is_numeric($rf) && is_numeric($rm)) {
				$s1 = $r - $rf;
				$eq_market_prem = $rm - $rf;
				if ($eq_market_prem > 0) {
					$bi = $s1 / $eq_market_prem;
				} else {
					$bi = 0;
				}
				$risk_prem = $bi * $eq_market_prem;
				$r_mr = ($rm * $bi) / $rf;

				$r_mrp = $r + $r_mr;
				$this->param['s1'] = $s1;
			} elseif ($cal === 'Rf' && is_numeric($r) && is_numeric($rm) && is_numeric($bi)) {
				$s1 = $bi * $rm;
				$s2 = $s1 - $r;
				$s3 = $bi - 1;
				$rf = $s2 / $s3;
				$eq_market_prem = $rm - $rf;
				$risk_prem = $bi * $eq_market_prem;
				$r_mr = ($rm * $bi) / $rf;
				$r_mrp = $r + $r_mr;
				$this->param['s1'] = $s1;
				$this->param['s2'] = $s2;
				$this->param['s3'] = $s3;
			} elseif ($cal === 'Rm' && is_numeric($r) && is_numeric($rf) && is_numeric($bi)) {
				$s1 = $bi - 1;
				$s2 = $rf * $s1;
				$s3 = $s2 + $r;
				$rm = $s3 / $bi;
				$eq_market_prem = $rm - $rf;
				$risk_prem = $bi * $eq_market_prem;
				$r_mr = ($rm * $bi) / $rf;
				$r_mrp = $r + $r_mr;



				$this->param['s1'] = $s1;
				$this->param['s2'] = $s2;
				$this->param['s3'] = $s3;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
			$this->param['cal'] = $cal;
			$this->param['R'] = $r;
			$this->param['Rp'] = $risk_prem;
			$this->param['Emp'] = $eq_market_prem;
			$this->param['Rf'] = $rf;
			$this->param['Rm'] = $rm;
			$this->param['Bi'] = $bi;
			$this->param['Rmr'] = round($r_mr, 3);
			$this->param['Rmrp'] = round($r_mrp, 3);
			$this->param['RESULT'] = 1;
			//   dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}
	/**********************
		OverTime Calculator/
	 **********************/
	function overtime($request)
	{
		// dd($request->all());
		$pay = $request->pay;
		$per = $request->per;
		$time = $request->time;
		$timeper = "h_m";
		$multi = $request->multi;
		$over = $request->over;
		$overper = $request->overper;

		if (is_numeric($request->pay) && $request->per && is_numeric($request->multi)) {
			$hourly = $pay;
			if ($per == 'hour') {
				$hourly = $hourly;
			} else if ($per == 'day') {
				$hourly = $hourly / 8;
			} elseif ($per == 'week') {
				$hourly = $hourly / 40;
			} else {
				$hourly = $hourly / 173.6;
			}
			$monthTime = $time;
			if ($timeper == 'h_m') {
				$monthTime = $monthTime;
			} elseif ($timeper == 'd_m') {
				$monthTime = ($monthTime * 8);
				// dd($monthTime);
			} elseif ($timeper == 'w_m') {
				$monthTime = $monthTime * 5 * 8;
			} elseif ($timeper == 'h_w') {
				$monthTime = $monthTime * 4.344;
			} elseif ($timeper == 'd_w') {
				$monthTime = ($monthTime * 8) * 4.345;
			} elseif ($timeper == 'h_d') {
				$monthTime = ($monthTime * 5) * 4.345;
			}
			$regPay = round($hourly * $monthTime, 2);
			// echo $regPay;die;

			$overPayPerHour = round($multi * $hourly, 2);
			$overHour = round($over, 2);
			$overHour = round($overHour, 2);
			$overTotalPay = round($overHour * $overPayPerHour, 2);

			$this->param['overPayPerHour'] = $overPayPerHour;
			$this->param['overTotalPay'] = $overTotalPay;
			$this->param['regPay'] = $regPay;
			$this->param['total'] = $overTotalPay + $regPay;
			$this->param['RESULT'] = 1;
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}
	/**********************
		OverTime Calculator/
	 **********************/
	function unemployment($request)
	{
		// dd($request->all());
		$employed_people = $request->employed_people;
		$unemployed_people = $request->unemployed_people;
		$adult_population = $request->adult_population;
		$calculate = $request->calculate;
		$labor_force = $request->labor_force;
		$unemployment_rate = $request->unemployment_rate;

		if ($calculate == "1") {
			$method = 1;
			if (is_numeric($employed_people) && is_numeric($unemployed_people)) {
				$cal_labor_force = $employed_people + $unemployed_people;
				$cal_unemployed_people = ($unemployed_people / $cal_labor_force) * 100;
				$this->param['labor_force'] = $cal_labor_force;
				$this->param['unemployment_rate'] = $cal_unemployed_people;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($calculate == "2") {
			$method = 2;
			if (is_numeric($labor_force) && is_numeric($unemployment_rate)) {
				$percent = $unemployment_rate / 100;
				$unemployment = $labor_force * $percent;
				$employment = $labor_force - $unemployment;
				$this->param['unemployment'] = $unemployment;
				$this->param['employment'] = $employment;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		if ($adult_population != "") {
			if (is_numeric($adult_population)) {
				$cal_labor_force = $employed_people + $unemployed_people;
				$labor_force_participation = ($cal_labor_force / $adult_population) * 100;
				$this->param['labor_force_participation'] = $labor_force_participation;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		$this->param['method'] = $method;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/**********************
		OverTime Calculator/
	 **********************/
	function cost($request)
	{
		// dd($request->all());
		$pay = $request->pay;
		$dividend_per_share = $request->dividend_per_share;
		$current_market_value = $request->current_market_value;
		$growth_rate_dividend = $request->growth_rate_dividend;
		$risk_rate_return = $request->risk_rate_return;
		$market_rate_return = $request->market_rate_return;
		$beta = $request->beta;

		if ($pay == "1") {
			if (is_numeric($dividend_per_share) && is_numeric($current_market_value) && is_numeric($growth_rate_dividend)) {
				$ans = ($dividend_per_share / $current_market_value) + $growth_rate_dividend / 100;
				$final_answer = $ans * 100;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($pay == "2") {
			if (is_numeric($risk_rate_return) && is_numeric($market_rate_return) && is_numeric($beta)) {
				$final_answer = $risk_rate_return + $beta * ($market_rate_return - $risk_rate_return);
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		$this->param['ans'] = $final_answer;
		$this->param['pay'] = $pay;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/************************
		Consumer Surplus calculator
	 ************************/
	function consumer($request)
	{
		// dd($request->all());
		$operations1 = $request->operations1;
		$operations2 = $request->operations2;
		$first = $request->first;
		$second = $request->second;
		$third = $request->third;
		$four = $request->four;
		$five = $request->five;

		if ($operations1 == "1") {
			if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
				$answer1 = $second - $first;
				$pmax = $second;
				$line1 = "Consumer Surplus";
				$ps = $answer1 + $five;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($operations1 == "2") {
			if (is_numeric($first) && is_numeric($second) && is_numeric($five)) {
				$answer1 = $second - $first;
				$pmax = $second;
				$ps = $first + $five;
				$line1 = "Actual Price";
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($operations1 == "3") {
			if (is_numeric($first) && is_numeric($second) && is_numeric($five)) {
				$answer1 = $second + $first;
				$pmax = $answer1;
				$ps = $first + $five;
				$line1 = "Willing Price";
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		if ($operations2 == 1) {
			if (is_numeric($third) && is_numeric($four)) {
				$mul1 = $four * 0.5;
				$answer2 = $mul1 - $pmax - $third;
				$line2 = "Extended Consumer Surplus";
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($operations2 == "2") {
			if (is_numeric($third) && is_numeric($four)) {
				$mul1 = 0.5 * $four;
				$answer2 = $mul1 - $pmax - $third;
				$line2 = "Equilibrium Price";
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($operations2 == "3") {
			if (is_numeric($third) && is_numeric($four)) {
				$div = $four / 0.5;
				$answer2 = $div + $pmax + $third;
				$line2 = "Equilibrium Quantity";
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		$this->param['answer1'] = $answer1;
		$this->param['answer2'] = $answer2;
		$this->param['line1'] = $line1;
		$this->param['ps'] = $ps;
		$this->param['line2'] = $line2;
		$this->param['operations1'] = $operations1;
		$this->param['operations2'] = $operations2;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/**********************
		Stock Caluclator
	 **********************/
	function stock($request)
	{

		// dd($request->all());
		$first = $request->first;
		$second = $request->second;
		$third = $request->third;
		$t_unit = $request->t_unit;
		$four = $request->four;
		$five = $request->five;
		$f_unit = $request->f_unit;
		$cgt = $request->cgt;
		$mycurrency = $request->mycurrency;

		if ($t_unit == '%') {
			$t_unit = '1';
		} else if ($t_unit == $mycurrency) {
			$t_unit = '0.01';
		}
		if ($f_unit == '%') {
			$f_unit = '1';
		} else if ($f_unit == $mycurrency) {
			$f_unit = '0.01';
		}
		// dd($t_unit);
		$third = $third * $t_unit;
		$five = $five * $f_unit;
		if (is_numeric($first) && is_numeric($second) && is_numeric($third) && is_numeric($four) && is_numeric($five) && is_numeric($cgt)) {
			if ($cgt > 0) {
				$div1 = $first / 100;
				$mul1 = $second * $third;
				if ($t_unit == 1) {
					$b_c = $div1 * $mul1;
				} elseif ($t_unit == 0.01) {
					$b_c = $third * 100;
				}
				$net_by = $second * $first;
				$netby_ans = $net_by + $b_c;
				$mul2 = $four * $five;
				if ($f_unit == 1) {
					$s_c = $div1 * $mul2;
				} elseif ($f_unit == 0.01) {
					$s_c = $five * 100;
				}
				$net_sa = $four * $first;
				$netsa_ans = $net_sa - $s_c;
				$profit = $netsa_ans - $netby_ans;
				$pro_per = ($profit / $cgt);
				$pro_ans = $profit - $pro_per;
				$roi = $profit / $netby_ans;
				$roi_ans = $roi * 100;
				$roi_ans1 = $roi_ans / $cgt;
				$roi_answer = $roi_ans - $roi_ans1;
				$per = $five / 100;
				$minus_per = 1 - $per;
				$mul_no = $first * $minus_per;
				$break_ans = $netby_ans / $mul_no;
			} else {
				$this->param['error'] = 'CGT Rate cannot be negative.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		$this->param['b_c'] = $b_c;
		$this->param['netby_ans'] = $netby_ans;
		$this->param['s_c'] = $s_c;
		$this->param['netsa_ans'] = $netsa_ans;
		$this->param['profit'] = $pro_ans;
		$this->param['roi_ans'] = $roi_answer;
		$this->param['break_ans'] = $break_ans;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/**********************
		ROAS Caluclator
	 **********************/
	function roas($request)
	{
		// dd($request->all());
		$first = $request->first;
		$hidden_currency = $request->hidden_currency;
		$operations1 = $request->operations1;
		$second = $request->second;
		$third = $request->third;

		if ($operations1 == 1) {
			if (is_numeric($first) && is_numeric($second)) {
				$divide1 = $second / $first;
				$answer1 = $divide1 * 100;
				if (is_numeric($third)) {
					$answer2 = $third - $first;
					$this->param['answer2'] = $answer2;
				}
				if ($answer1 > 0 && $answer1 < 400) {
					$line = "❌ Danger! Your ROAS is " . number_format($answer1, 2) . "% that is alarming. If return is less than 400% ROAS, you are in loss. So you actually spend more on ad campaign. ";
				} else if ($answer1 >= 400 && $answer1 < 800) {
					$line = "🚫 Your ROAS is " . number_format($answer1, 2) . "% that is fair enough. But you must target 800% and spend more than before in ads. ";
				} else if ($answer1 >= 800) {
					$line = "✔ Great! Your ROAS is " . number_format($answer1, 2) . "% that is fairly good enough.";
				}
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($operations1 == 2) {
			if (is_numeric($first)) {
				if ($first > 0) {
					$answer1 = $first * 8;
					$answer2 = $answer1 * 10;
					$line = " ✅ Aim for "  . $hidden_currency .  " " . $answer1 . " as climbing 800% ROAS will let you earn good initiatives. ";
					$this->param['answer2'] = $answer2;
				} else {
					$this->param['error'] = 'Money spent on ads cannot be negative or zero';
					return $this->param;
				}
			} else {

				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
		$this->param['answer1'] = $answer1;
		$this->param['line'] = $line;
		$this->param['first'] = $first;
		$this->param['second'] = $second;
		$this->param['operations1'] = $operations1;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/**********************
		ROAS Caluclator
	 **********************/
	function pay($request)
	{
		// dd($request->all());
		$pay = $request->pay;
		$period = $request->period;
		$hour = $request->hour;
		$type = $request->type;
		$new = $request->new;

		if (is_numeric($pay) && is_numeric($hour) && is_numeric($new)) {
			if ($period == 1) {
				$hourly = $pay;
				$weekly = $pay * $hour;
				$monthly = round(($weekly * 4) + (($hourly * ($hour / 6)) * 2), 2);
				$yearly = round($monthly * 12);
			} elseif ($period == 2) {
				$hourly = $pay / $hour;
				$weekly = $pay;
				$monthly = round(($weekly * 4) + (($hourly * ($hour / 6)) * 2), 2);
				$yearly = round($monthly * 12);
			} elseif ($period == 3) {
				$monthly = $pay;
				$yearly = round($pay * 12);
				$weekly = round(($monthly / 26) * 6, 2);
				$hourly = round($weekly / $hour, 2);
			} elseif ($period == 4) {
				$yearly = $pay;
				$monthly = round($pay / 12);
				$weekly = round(($monthly / 26) * 6, 2);
				$hourly = round($weekly / $hour, 2);
			}
			if ($type == 1) {
				$incHour = ($hourly * ($new / 100));
				$incWeek = ($weekly * ($new / 100));
				$incMonth = ($monthly * ($new / 100));
				$incYear = ($yearly * ($new / 100));
				$percent = $new;
			} else {
				if ($period == 1) {
					$percent = ($new / $hourly) * 100;
				} elseif ($period == 2) {
					$percent = ($new / $weekly) * 100;
				} elseif ($period == 3) {
					$percent = ($new / $monthly) * 100;
				} elseif ($period == 4) {
					$percent = ($new / $yearly) * 100;
				}
				$incHour = ($hourly * ($percent / 100));
				$incWeek = ($weekly * ($percent / 100));
				$incMonth = ($monthly * ($percent / 100));
				$incYear = ($yearly * ($percent / 100));
			}
			$this->param['percent'] = $percent;
			$this->param['incHour'] = $incHour;
			$this->param['incWeek'] = $incWeek;
			$this->param['incMonth'] = $incMonth;
			$this->param['incYear'] = $incYear;
			$this->param['hourly'] = $hourly;
			$this->param['weekly'] = $weekly;
			$this->param['monthly'] = $monthly;
			$this->param['yearly'] = $yearly;
			$this->param['type'] = $type;
			$this->param['RESULT'] = 1;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}

	/**********************
		Gross Income Calculator
	 **********************/
	function gross($request)
	{
		// dd($request->all());
		$pay_frequency = $request->pay_frequency;
		$type          = $request->type;
		$pay_method    = $request->pay_method;
		$amount        = $request->amount;
		$filer_status  = $request->filer_status;



		if (!empty($pay_frequency) && !empty($type) && !empty($filer_status) && !empty($pay_method) && is_numeric($amount)) {
			if ($type == "Bonus") {
				$total_amount = $amount;
			} else {
				if ($pay_method == "Per-Year") {
					$total_amount = $amount;
				} else {
					if ($pay_frequency == "Daily") {
						$total_amount = $amount * (365 - 104);
					} else if ($pay_frequency == "Weekly") {
						$total_amount = $amount * 52;
					} else if ($pay_frequency == "Bi-Weekly") {
						$total_amount = $amount * 26;
					} else if ($pay_frequency == "Semi-Monthly") {
						$total_amount = $amount * 24;
					} else if ($pay_frequency == "Monthly") {
						$total_amount = $amount * 12;
					} else if ($pay_frequency == "Quarterly") {
						$total_amount = $amount * 4;
					} else {
						$total_amount = $amount;
					}
				}
			}

			if ($pay_frequency == "Daily") {
				$per_frequency = round($total_amount / (365 - 104), 2);
			} else if ($pay_frequency == "Weekly") {
				$per_frequency = round($total_amount / 52, 2);
			} else if ($pay_frequency == "Bi-Weekly") {
				$per_frequency = round($total_amount / 26, 2);
			} else if ($pay_frequency == "Semi-Monthly") {
				$per_frequency = round($total_amount / 24, 2);
			} else if ($pay_frequency == "Monthly") {
				$per_frequency = round($total_amount / 12, 2);
			} else if ($pay_frequency == "Quarterly") {
				$per_frequency = round($total_amount / 4, 2);
			} else {
				$per_frequency = $total_amount;
			}

			$secrity_per               = 6.20;
			$secrity_amount_frequency  = $per_frequency * 0.062;
			$secrity_amount_yearly     = $total_amount * 0.062;
			$medicare_per              = 1.45;
			$medicare_amount_frequency = $per_frequency * 0.0145;
			$medicare_amount_yearly    = $total_amount * 0.0145;

			if ($filer_status == "single") {
				if ($total_amount > 0 && $total_amount <= 10275) {
					$tax_per              = 10;
