	/**********************
		Turo Caluclator
	 **********************/
	function turo($request)
	{
		// dd($request->all());
		$type = $request->type;
		$operations = $request->operations;
		$first = $request->first;
		$second = $request->second;
		$third = $request->third;
		$four = $request->four;
		$f_first = $request->f_first;
		$f_second = $request->f_second;
		$f_third = $request->f_third;

		if ($type == "first") {
			if (is_numeric($f_first) && is_numeric($f_second) && is_numeric($f_third)) {
				$multiply = $f_third * $f_second;
				$answer = $multiply - $f_first;
				$heading = "Turo Profit";
			} else {
				$this->param['error'] = 'Please fill all fields.';
				$this->param['type'] = $type;
				return $this->param;
			}
		} elseif ($type == "second") {
			if ($operations == "1") {
				if (is_numeric($first) && is_numeric($second)) {
					$answer = $first * $second;
					$heading = "Income";
				} else {
					$this->param['error'] = 'Please fill all fields.';
					$this->param['type'] = $type;
					$this->param['operations'] = $operations;
					return $this->param;
				}
			} elseif ($operations == "2") {
				if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
					$divide = $first / $third;
					$answer = $divide + $second;
					$answer = round($answer, 2);
					$heading = "Lease Details";
				} else {
					$this->param['error'] = 'Please fill all fields.';
					$this->param['type'] = $type;
					$this->param['operations'] = $operations;
					return $this->param;
				}
			} elseif ($operations == "3") {
				if (is_numeric($first) && is_numeric($second) && is_numeric($third) && is_numeric($third)) {
					$answer = $first + $second + 50 + $four;
					$heading = "Expenses";
				} else {
					$this->param['error'] = 'Please fill all fields.';
					return $this->param;
					$this->param['type'] = $type;
					$this->param['operations'] = $operations;
				}
			}
		}
		$this->param['answer'] = $answer;
		$this->param['heading'] = $heading;
		$this->param['type'] = $type;
		$this->param['operations'] = $operations;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/**********************
		Turo Caluclator
	 **********************/

	function commission($request)
	{
		// dd($request->all());
		$find = $request->find;
		$select1 = $request->select1;
		$sale_price = $request->sale_price;
		$commission_rate = $request->commission_rate;
		$commission_amount = $request->commission_amount;

		if ($find == "1" || $find == "2") {
			$method = 1;
			if ($select1 == "commission") {
				if (is_numeric($sale_price) && is_numeric($commission_rate) && $sale_price > 0 && $commission_rate > 0) {
					$answer = ($sale_price * $commission_rate) / 100;
					$this->param['sale_price'] = $sale_price;
					$this->param['commission_rate'] = $commission_rate;
				} else {
					$this->param['error'] = 'Please fill all fields.';
					return $this->param;
				}
			} else if ($select1 == "sale_price") {
				$method = 2;
				if (is_numeric($commission_rate) && is_numeric($commission_amount) && $commission_rate > 0 && $commission_amount > 0) {
					$answer = ($commission_amount / $commission_rate) * 100;
					$this->param['commission_rate'] = $commission_rate;
					$this->param['commission_amount'] = $commission_amount;
				} else {
					$this->param['error'] = 'Please fill all fields.';
					return $this->param;
				}
			} else if ($select1 == "commission_rate") {
				$method = 3;
				if (is_numeric($sale_price) && is_numeric($commission_amount) && $sale_price > 0 && $commission_amount > 0) {
					$answer = ($commission_amount / $sale_price) * 100;
					$this->param['sale_price'] = $sale_price;
					$this->param['commission_amount'] = $commission_amount;
				} else {
					$this->param['error'] = 'Please fill all fields.';
					return $this->param;
				}
			}
		}
		$this->param['calculate'] = $find;
		$this->param['find'] = $method;
		$this->param['ans'] = $answer;
		$this->param['select1'] = $select1;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/**********************
		Marginal Cost Calculator
	 **********************/
	function marginal($request)
	{
		// dd($request->all());
		if ($request->unit_type === 'sr') {  
			$dc = $request->dc;
			$dq = $request->dq;
			$dq_unit = $request->dq_unit;
			$sr = $request->unit_type;
		} else {
			$cc = $request->cc;
			$fc = $request->fc;
			$cq = $request->cq;
			$cq_unit = $request->cq_unit;
			$fq = $request->fq;
			$fq_unit = $request->fq_unit;
			$gr = $request->unit_type;
		}
		// dd($request->all());
		if (isset($sr)) {
			if (is_numeric($dc) && is_numeric($dq) && !empty($dq_unit)) {
				$check = true;
			} else {
				$check = false;
			}
		} else {
			if (is_numeric($cc) && is_numeric($fc) && is_numeric($cq) && is_numeric($fq) && !empty($cq_unit) && !empty($fq_unit)) {
				$check = true;
			} else {
				$check = false;
			}
		}
		if ($check === true) {
			if (isset($dq)) {
				if ($dq_unit === 'pairs') {
					$dq = $dq * 2;
				} elseif ($dq_unit === 'decades') {
					$dq = $dq * 10;
				} elseif ($dq_unit === 'dozens') {
					$dq = $dq * 12;
				}
			}
			if (isset($cq)) {
				if ($cq_unit === 'pairs') {
					$cq = $cq * 2;
				} elseif ($cq_unit === 'decades') {
					$cq = $cq * 10;
				} elseif ($cq_unit === 'dozens') {
					$cq = $cq * 12;
				}
			}
			if (isset($fq)) {
				if ($fq_unit === 'pairs') {
					$fq = $fq * 2;
				} elseif ($fq_unit === 'decades') {
					$fq = $fq * 10;
				} elseif ($fq_unit === 'dozens') {
					$fq = $fq * 12;
				}
			}
			if (isset($sr)) {
				if (is_numeric($dc) && is_numeric($dq)) {
					$mc = $dc / $dq;
					$this->param['check'] = 'm1';
				}
			} elseif (isset($gr)) {
				if (is_numeric($cc) && is_numeric($fc) && is_numeric($cq) && is_numeric($fq)) {
					$dc = $fc - $cc;
					$dq = $fq - $cq;
					$mc = $dc / $dq;
					$this->param['check'] = 'm2';
					$this->param['cc'] = $cc;
					$this->param['fc'] = $fc;
					$this->param['cq'] = $cq;
					$this->param['fq'] = $fq;
					$this->param['mc'] = $mc;
					$this->param['dq'] = $dq;
					$this->param['dc'] = $dc;
					$this->param['RESULT'] = 1;
					// dd($this->param);
					return $this->param;
				}
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
			$this->param['mc'] = $mc;
			$this->param['dc'] = $dc;
			$this->param['dq'] = $dq;
			$this->param['RESULT'] = 1;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
	}

	/*******************
    Variable Cost Calculator
	 *******************/
	function variable($request)
	{
		$type = $request->type;
		$cost = $request->cost;
		$output = $request->output;

		if (!empty($type)) {
			if ($type == 'average_cost') {
				if (is_numeric($cost) && is_numeric($output)) {
					$av_cost = $cost / $output;
					$this->param['cost'] = $cost;
					$this->param['output'] = $output;
					$this->param['av_cost'] = $av_cost;
				} else {
					$this->param['error'] = 'Please fill all fields.';
					return $this->param;
				}
			} else if ($type == 'variable_cost') {
				if (is_numeric($cost) && is_numeric($output)) {
					$v_cost = $cost - $output;
					$this->param['cost'] = $cost;
					$this->param['output'] = $output;
					$this->param['v_cost'] = $v_cost;
				} else {
					$this->param['error'] = 'Please fill all fields.';
					return $this->param;
				}
			}
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		$this->param['type'] = $type;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/*******************
   Labor Cost Calculator
	 *******************/
	function labor($request)
	{
		// dd($request->all());
		$h_p_w = $request->h_p_w;
		$p_r = $request->p_r;
		$a_d_p_y = $request->a_d_p_y;
		$tax = $request->tax;
		$insurance = $request->insurance;
		$benefits = $request->benefits;
		$overtime = $request->overtime;
		$supplies = $request->supplies;
		$total_revenue = $request->total_revenue;


		if (
			is_numeric($h_p_w) && is_numeric($p_r) && is_numeric($a_d_p_y) && is_numeric($tax) && is_numeric($insurance)
			&& is_numeric($benefits) && is_numeric($overtime) && is_numeric($supplies) && is_numeric($total_revenue)
		) {
			$g_h_per_year = $h_p_w * 52;
			$gross_pay = $g_h_per_year * $p_r;
			$n_w_p_year = $a_d_p_y * 8;
			$net_h_work = $g_h_per_year - $n_w_p_year;
			$annual_cost = $tax + $insurance + $benefits + $overtime + $supplies;
			$annual_p_labor_cost = $gross_pay + $annual_cost;
			$h_l_cost = $annual_p_labor_cost / $net_h_work;
			$l_c_percentge = $annual_p_labor_cost / $total_revenue;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		$this->param['annual_p_labor_cost'] = $annual_p_labor_cost;
		$this->param['h_l_cost'] = $h_l_cost;
		$this->param['h_p_w'] = $h_p_w;
		$this->param['p_r'] = $p_r;
		$this->param['a_d_p_y'] = $a_d_p_y;
		$this->param['tax'] = $tax;
		$this->param['insurance'] = $insurance;
		$this->param['benefits'] = $benefits;
		$this->param['overtime'] = $overtime;
		$this->param['supplies'] = $supplies;
		$this->param['total_revenue'] = $total_revenue;
		$this->param['g_h_per_year'] = $g_h_per_year;
		$this->param['gross_pay'] = $gross_pay;
		$this->param['n_w_p_year'] = $n_w_p_year;
		$this->param['net_h_work'] = $net_h_work;
		$this->param['annual_cost'] = $annual_cost;
		$this->param['l_c_percentge'] = $l_c_percentge;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/*******************
		NPS Calculator
	 *******************/
	function nps($request)
	{
		// dd($request->all());
		$score_ten = trim($request->score_ten);
		$score_nine = trim($request->score_nine);
		$score_eight = trim($request->score_eight);
		$score_seven = trim($request->score_seven);
		$score_six = trim($request->score_six);
		$score_five = trim($request->score_five);
		$score_four = trim($request->score_four);
		$score_three = trim($request->score_three);
		$score_two = trim($request->score_two);
		$score_one = trim($request->score_one);
		$score_zero = trim($request->score_zero);


		if (is_numeric($score_ten) && is_numeric($score_nine) && is_numeric($score_eight) && is_numeric($score_seven) && is_numeric($score_six) && is_numeric($score_five) && is_numeric($score_four) && is_numeric($score_three) && is_numeric($score_two) && is_numeric($score_one) && is_numeric($score_zero)) {
			$good = $score_ten + $score_nine;
			$neutral = $score_eight + $score_seven;
			$bad = $score_six + $score_five + $score_four + $score_three + $score_two + $score_one + $score_zero;
			$total = $good + $neutral + $bad;
			if ($total == 0) {
				$this->param['error'] = 'Check Your Input Total nps not equal to zero';
				return $this->param;
			}
			$answer = ($good / $total - $bad / $total) * 100;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		$this->param['good'] = $good;
		$this->param['neutral'] = $neutral;
		$this->param['bad'] = $bad;
		$this->param['total'] = $total;
		$this->param['answer'] = $answer;
		$this->param['score_ten'] = $score_ten;
		$this->param['score_nine'] = $score_nine;
		$this->param['score_eight'] = $score_eight;
		$this->param['score_seven'] = $score_seven;
		$this->param['score_six'] = $score_six;
		$this->param['score_five'] = $score_five;
		$this->param['score_four'] = $score_four;
		$this->param['score_three'] = $score_three;
		$this->param['score_two'] = $score_two;
		$this->param['score_one'] = $score_one;
		$this->param['score_zero'] = $score_zero;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/*******************
		VA Disability Calculator
	 *******************/
	function va($request)
	{
	// dd($request->all());
		$right_arm = trim($request->right_arm);
		$left_arm = trim($request->left_arm);
		$right_leg = trim($request->right_leg);
		$left_leg = trim($request->left_leg);
		$right_foot = trim($request->right_foot);
		$left_foot = trim($request->left_foot);
		$back = trim($request->back);
		$ssd = trim($request->ssd);
		$ptsd = trim($request->ptsd);
		$tinnitus = trim($request->tinnitus);
		$migraines = trim($request->migraines);
		$sleep_apnea = trim($request->sleep_apnea);
		$bilateral_upper = trim($request->bilateral_upper);
		$bilateral_lower = trim($request->bilateral_lower);
		$others = trim($request->others);
		$status = trim($request->status);
		$attendance = trim($request->attendance);
		$under_age = trim($request->under_age);
		$over_age = trim($request->over_age);
		$parent = trim($request->parent);


		$disabilities = [$right_arm, $left_arm, $right_leg, $left_leg, $right_foot, $left_foot, $back, $ssd, $ptsd, $tinnitus, $migraines, $sleep_apnea, $bilateral_upper, $bilateral_lower, $others];

		$filteredDisabilities = array_filter($disabilities, function ($value) {
			return $value !== '0';
		});

		$newDisabilitiesArray = array_values($filteredDisabilities);

		$arraytotal = count($newDisabilitiesArray);

		rsort($newDisabilitiesArray);

		if ($arraytotal == 0) {
			$this->param['error'] = 'Please! select disability';
			return $this->param;
		} elseif ($arraytotal == 1) {
			$total_cumulative = end($newDisabilitiesArray);
		} elseif ($arraytotal == 2) {
			$val_first = reset($newDisabilitiesArray);
			$val_sec = end($newDisabilitiesArray);

			$a = ((100 - $val_first) * $val_sec) / 100;
			$cdis = round($val_first + $a);
			$answers[] = round($cdis);
			$total_cumulative = end($answers);
		} else {
			for ($i = 0; $i < ($arraytotal - 1); $i++) {
				if ($i === 0) {
					$a = ((100 - $newDisabilitiesArray[$i]) * $newDisabilitiesArray[$i + 1]) / 100;
					$cdis = round($newDisabilitiesArray[$i] + $a);
				}
				if (($i !== 0)) {
					$jawab = ((100 - $cdis) * $newDisabilitiesArray[$i + 1]) / 100;
					$cdis = $cdis + $jawab;
					$answers[] = round($cdis);
				}
			}
			$total_cumulative = end($answers);
		}
		if ($total_cumulative < 15) {
			$total_combined = 10;
			$total_combined_index = 0;
		} elseif ($total_cumulative < 25) {
			$total_combined = 20;
			$total_combined_index = 1;
		} elseif ($total_cumulative < 35) {
			$total_combined = 30;
			$total_combined_index = 2;
		} elseif ($total_cumulative < 45) {
			$total_combined = 40;
			$total_combined_index = 3;
		} elseif ($total_cumulative < 55) {
			$total_combined = 50;
			$total_combined_index = 4;
		} elseif ($total_cumulative < 65) {
			$total_combined = 60;
			$total_combined_index = 5;
		} elseif ($total_cumulative < 75) {
			$total_combined = 70;
			$total_combined_index = 6;
		} elseif ($total_cumulative < 85) {
			$total_combined = 80;
			$total_combined_index = 7;
		} elseif ($total_cumulative < 95) {
			$total_combined = 90;
			$total_combined_index = 8;
		} else {
			$total_combined = 100;
			$total_combined_index = 9;
		}
		$model = [
			'alone' => [171.23, 338.49, 524.31, 755.28, 1075.16, 1361.88, 1716.28, 1995.01, 2241.91, 3737.85],
			'VeteranChild' => [171.23, 338.49, 565.31, 810.28, 1144.16, 1444.88, 1813.29, 2106.01, 2366.91, 3877.22],
			'veteranparent' => [171.23, 338.49, 574.31, 821.28, 1158.16, 1461.88, 1833.28, 2128.01, 2391.91, 3905.11],
			'VeteranSpouse' => [171.23, 338.49, 586.31, 838.28, 1179.16, 1486.88, 1861.28, 2161.01, 2428.91, 3946.25],
			'VeteranParentChild' => [171.23, 338.49, 615.31, 876.28, 1227.16, 1544.88, 1930.28, 2239.01, 2516.91, 4044.48],
			'VeterantwoParents' => [171.23, 338.49, 624.31, 887.28, 1241.16, 1561.88, 1950.28, 2261.01, 2541.91, 4072.37],
			'VeteranSpouseChild' => [171.23, 338.49, 632.31, 899.28, 1255.16, 1577.88, 1968.28, 2283.01, 2565.91, 4098.87],
			'VeteranspouseoneParent' => [171.23, 338.49, 636.31, 904.28, 1262.16, 1586.88, 1978.28, 2294.01, 2578.91, 4113.51],
			'VeterantwoParentsChild' => [171.23, 338.49, 665.31, 942.28, 1310.16, 1644.88, 2047.28, 2372.01, 2666.91, 4211.74],
			'VeteranspouseoneParentoneChild' => [171.23, 338.49, 682.31, 965.28, 1338.16, 1677.88, 2085.28, 2416.01, 2715.91, 4266.13],
			'VeteranSpousetwoParents' => [171.23, 338.49, 688.31, 970.28, 1345.16, 1686.88, 2095.28, 2427.01, 2727.91, 4280.77],
			'VeteranSpousetwoParentsoneChild' => [171.23, 338.49, 732.31, 1031.28, 1421.16, 1777.88, 2202.28, 2549.01, 2865.91, 4433.39],
			'additionalchildrenunderage' => [0.00, 0.00, 31.00, 41.00, 51.00, 62.00, 72.00, 82.00, 93.00, 103.55],
			'overagechildren' => [0.00, 0.00, 100.00, 133.00, 167.00, 200.00, 234.00, 267.00, 301.00, 334.49],
			'aidandattendance' => [0.00, 0.00, 57.00, 76.00, 95.00, 114.00, 134.00, 153.00, 172.00, 191.14],
		];
		if ($status === "Single") {
			$rate = $model['alone'][$total_combined_index];
		}
		if ($status === "Single" && $under_age === '1' xor $over_age === '1') {
			$rate = $model['VeteranChild'][$total_combined_index];
		}
		if ($status === "Single" && $parent === '1') {
			$rate = $model['veteranparent'][$total_combined_index];
		}
		if ($status === "Single" && $parent === '2') {
			$rate = $model['VeterantwoParents'][$total_combined_index];
		}
		if ($status === "Single" && $parent === '1' &&  $under_age === '1' xor $over_age === '1') {
			$rate = $model['VeteranParentChild'][$total_combined_index];
		}
		if ($status === "Single"  && $parent === '2' && $under_age === '1' xor $over_age === '1') {
			$rate = $model['VeterantwoParentsChild'][$total_combined_index];
		}
		if ($status === "Married") {
			$rate = $model['VeteranSpouse'][$total_combined_index];
		}
		if ($status === "Married" &&  $under_age === '1' xor $over_age === '1') {
			$rate = $model['VeteranSpouseChild'][$total_combined_index];
		}
		if ($status === "Married"  && $parent === '1') {
			$rate = $model['VeteranspouseoneParent'][$total_combined_index];
		}
		if ($status === "Married"  && $parent === '1' && $under_age === '1' xor $over_age === '1') {
			$rate = $model['VeteranspouseoneParentoneChild'][$total_combined_index];
		}
		if ($status === "Married"  && $parent === '2') {
			$rate = $model['VeteranSpousetwoParents'][$total_combined_index];
		}
		if ($status === "Married"  && $parent === '2' && $under_age === '1' xor $over_age === '1') {
			$rate = $model['VeteranSpousetwoParentsoneChild'][$total_combined_index];
		}
		if ($attendance === 'Yes') {
			$rate = $rate + $model['aidandattendance'][$total_combined_index];
		}
		// For Under AGE
		if ($under_age !== '1') {
			$rate = $rate + ($under_age * $model['additionalchildrenunderage'][$total_combined_index]);
		}
		// For oVER aGE AGE
		if ($over_age !== '1') {
			$rate = $rate + ($over_age * $model['overagechildren'][$total_combined_index]);
		}
		$this->param['total_cumulative'] = $total_cumulative;
		$this->param['total_combined'] = $total_combined;
		$this->param['rate'] = $rate;
		$this->param['status'] = $status;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/*******************
   		Wedding Budget Calculator
	 *******************/
	function wedding($request)
	{
		// dd($request->all());
		$spend = trim($request->spend);
		$guest = trim($request->guest);
		$dress = trim($request->dress) ?: 0;
		$jewelery = trim($request->jewelery) ?: 0;
		$accessories = trim($request->accessories) ?: 0;
		$ring = trim($request->ring) ?: 0;
		$makeup = trim($request->makeup) ?: 0;
		$stationery = trim($request->stationery) ?: 0;
		$photography = trim($request->photography) ?: 0;
		$florist = trim($request->florist) ?: 0;
		$planner = trim($request->planner) ?: 0;
		$venue = trim($request->venue) ?: 0;
		$dinner = trim($request->dinner) ?: 0;
		$catering = trim($request->catering) ?: 0;
		$cake = trim($request->cake) ?: 0;
		$DJs = trim($request->DJs) ?: 0;
		$liquors = trim($request->liquors) ?: 0;
		$ceremony = trim($request->ceremony) ?: 0;
		$officiant = trim($request->officiant) ?: 0;
		$hotel = trim($request->hotel) ?: 0;
		$transportation = trim($request->transportation) ?: 0;
		$other = trim($request->other) ?: 0;
		$clickvalue1 = trim($request->clickvalue1) ?: 0;
		$clickvalue2 = trim($request->clickvalue2) ?: 0;
		$clickvalue3 = trim($request->clickvalue3) ?: 0;
		$clickvalue4 = trim($request->clickvalue4) ?: 0;
		$clickvalue5 = trim($request->clickvalue5) ?: 0;


		if (is_numeric($spend) && is_numeric($guest)) {

			$bride_groom = $dress + $jewelery + $accessories + $ring + $makeup;
			$sub_contractors = $stationery + $photography + $florist + $planner;
			$food_drinks = $venue + $dinner + $catering + $cake + $DJs + $liquors;
			$ceremony_total = $ceremony + $officiant;
			$trans_accomo = $hotel + $transportation;
			$total = $bride_groom + $sub_contractors + $food_drinks + $ceremony_total + $trans_accomo;
			$average_cost = ($total + $other) / $guest;
			$budget_balance = $spend - $total;

			$this->param['average_cost'] = $average_cost;
			$this->param['budget_balance'] = $budget_balance;
			$this->param['bride_groom'] = $bride_groom;
			$this->param['sub_contractors'] = $sub_contractors;
			$this->param['food_drinks'] = $food_drinks;
			$this->param['ceremony_total'] = $ceremony_total;
			$this->param['trans_accomo'] = $trans_accomo;
			$this->param['other'] = $other;
			$this->param['spend'] = $spend;
			$this->param['dress'] = $dress;
			$this->param['jewelery'] = $jewelery;
			$this->param['accessories'] = $accessories;
			$this->param['ring'] = $ring;
			$this->param['makeup'] = $makeup;
			$this->param['clickvalue1'] = $clickvalue1;
			$this->param['clickvalue2'] = $clickvalue2;
			$this->param['clickvalue3'] = $clickvalue3;
			$this->param['clickvalue4'] = $clickvalue4;
			$this->param['clickvalue5'] = $clickvalue5;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}
