				$rolls_input = array();
			}
			foreach ($rolls_values as $key => $value) {
				if (is_numeric($rolls[$key])) {
					$rolls_total[] = $value * $rolls[$key] * $rolls_count[$key];
					$rolls_quantity[] = $value;
					$rolls_input[] = $rolls[$key];
					$rolls_count_ans[] = $rolls_count[$key];
				}
			}
			$this->param['rolls_total'] = $rolls_total;
			$this->param['rolls_quantity'] = $rolls_quantity;
			$this->param['rolls_input'] = $rolls_input;
			if (isset($rolls_count_ans)) {
				$this->param['rolls_count_ans'] = $rolls_count_ans;
			}
		}

		$total_money = array_sum($coins_total) + array_sum($note_total) + array_sum($rolls_total);

		$this->param['total_money'] = round($total_money, 2);
		$this->param['note_total'] = $note_total;
		$this->param['note_quantity'] = $note_quantity;
		$this->param['note_input'] = $note_input;

		$this->param['coins_total'] = $coins_total;
		$this->param['coins_quantity'] = $coins_quantity;
		$this->param['coins_input'] = $coins_input;

		$this->param['ans_currency'] = $ans_currency;
		$this->param['checkbox1'] = $checkbox1;
		$this->param['checkbox2'] = $checkbox2;
		$this->param['checkbox3'] = $checkbox3;
		$this->param['currency'] = $currency;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}

	/**********************
		NPV Calculator
	 **********************/
	function npv($request)
	{
		// dd($request->all());
		$initial = $request->initial;
		$discount = $request->discount;
		$year = $request->year;

		$discount = $discount / 100;
		if (is_numeric($initial) && is_numeric($initial)) {
			for ($i = 1; $i <= count($year); $i++) {
				$npv_btm = pow((1 + $discount), $i);
				$all_npv[] = $year[$i - 1] / $npv_btm;
			}
			$npv_ans = (array_sum($all_npv)) - $initial;
			$total_return = array_sum($year) - $initial;
			$gross_return = ($total_return / $initial) * 100;
			$net_cash_flow = ($initial / 100) * $gross_return;
			// for chart calculation
			// $dataPoints[0] = ["y" => $initial,"label" => 'Initial Investment'];
			// Assuming both arrays have the same length
			for ($i = 0; $i < count($year); $i++) {
				$dataPoints[$i] = [
					"y" => (int)$year[$i],
					"label" => 'Year ' . ($i + 1),
				];
			}
			$dataPoints = json_encode($dataPoints);
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		$this->param['npv_ans'] = round($npv_ans, 2);
		$this->param['gross_return'] = round($gross_return, 2);
		$this->param['net_cash_flow'] = round($net_cash_flow, 2);
		$this->param['dataPoints'] = $dataPoints;
		$this->param['year'] = $year;
		$this->param['RESULT'] = 1;
		$this->param['arrayLength'] = count($year);
		// dd($this->param);
		return $this->param;
	}

	function ebitda($request)
	{
		// dd($request->all());
		if ($request->unit_type === 'simple') {
			if (is_numeric($request->x) && is_numeric($request->y) && is_numeric($request->a) && is_numeric($request->d)) {
				$ebitda = $request->x - $request->y + $request->a + $request->d;
				$margin = round(($ebitda / $request->x) * 100, 2);
				$this->param['ebitda'] = $ebitda;
				$this->param['margin'] = $margin . " %";
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else if ($request->unit_type === 'extended') {
			if (is_numeric($request->rev) && is_numeric($request->net) && is_numeric($request->Interest) && is_numeric($request->Taxes) && is_numeric($request->ae) && is_numeric($request->de)) {
				$ebitda = $request->net + $request->Interest + $request->Taxes + $request->de + $request->ae;
				$margin = round(($ebitda / $request->rev) * 100, 2);
				$this->param['ebitda'] = $ebitda;
				$this->param['extended'] = 'active';
				$this->param['margin'] = $margin . " %";
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		}
	}

	/*******************
		cagr-calculator
	 *******************/
	public function cagr($request)
	{
		// dd($request->all());
		$units = trim($request->unit_type);
		$starting_first = trim($request->starting_first);
		$ending_first = trim($request->ending_first);
		$years_first = trim($request->years_first);
		$months_first = trim($request->months_first);
		$days_first = trim($request->days_first);
		$starting_sec = trim($request->starting_sec);
		$ending_sec = trim($request->ending_sec);
		$start_date = trim($request->start_date);
		$ending_date = trim($request->ending_date);
		$starting_third = trim($request->starting_third);
		$cagr = trim($request->cagr);
		$years_third = trim($request->years_third);
		$months_third = trim($request->months_third);
		$days_third = trim($request->days_third);

		if ($starting_first >= $ending_first) {
			$this->param['error'] = 'ending value is greater than or not equal to starting value.';
			return $this->param;
		}
		if (empty($years_first) && empty($months_first) && empty($days_first)) {
			$this->param['error'] = 'Please! Check Enter Input.';
			return $this->param;
		}
		if (empty($years_first)) {
			$years_first = 0;
		}
		if (empty($months_first)) {
			$months_first = 0;
		}
		if (empty($days_first)) {
			$days_first = 0;
		}
		if (empty($years_third) && empty($months_third) && empty($days_third)) {
			$this->param['error'] = 'Please! Check Enter Input.';
			return $this->param;
		}
		if (empty($years_third)) {
			$years_third = 0;
		}
		if (empty($months_third)) {
			$months_third = 0;
		}
		if (empty($days_third)) {
			$days_third = 0;
		}
		function calculateTotalDays($years, $months, $days)
		{
			$total_days = $years * 365 + $months * 30 + $days;
			return $total_days;
		}
		if (empty($start_date)) {
			$this->param['error'] = 'Please! Check Start Date Input.';
			return $this->param;
		}
		if (empty($ending_date)) {

			$this->param['error'] = 'Please! Check Ending Date Input.';
			return $this->param;
		}
		if ($starting_sec >= $ending_sec) {
			$this->param['error'] = 'ending value is greater than or not equal to starting value.';
			return $this->param;
		}
		function calculateDateDifference($start_date, $ending_date)
		{
			$start_datetime = new DateTime($start_date);
			$end_datetime = new DateTime($ending_date);
			$interval = $start_datetime->diff($end_datetime);
			return $interval->format('%a');
		}
		if ($units === 'one') {
			if (is_numeric($starting_first) && is_numeric($ending_first)) {
				$total_days = calculateTotalDays($years_first, $months_first, $days_first);
				if ($total_days <= 0) {
					$this->param['error'] = 'Please! add at least one day';
					return $this->param;
				}
				$cagr = pow($ending_first / $starting_first, 365 / $total_days) - 1;
				$double = log(2, M_E) / log(1 + $cagr, M_E);
				$yearx = floor($double);
				$fractional_part = $double - $yearx;
				$total_dayz = $fractional_part * 365;
				$monthz = floor($total_dayz / 30);
				$dayz = round($total_dayz % 30);
				$table_year = $total_days / 365;
				$cagr_percentage = $cagr * 100;
				if ($years_first <= "1") {
					$year = $years_first . " year";
				} else {
					$year = $years_first . " years";
				}
				if ($months_first <= "1") {
					$months = $months_first . " month";
				} else {
					$months = $months_first . " months";
				}
				if ($days_first <= "1") {
					$days = $days_first . " day";
				} else {
					$days = $days_first . " days";
				}

				$this->param['total_days'] = $total_days;
				$this->param['cagr_percentage'] = $cagr_percentage;
				$this->param['year'] = $year;
				$this->param['months'] = $months;
				$this->param['days'] = $days;
				$this->param['dayz'] = $dayz;
				$this->param['monthz'] = $monthz;
				$this->param['yearx'] = $yearx;
				$this->param['table_year'] = $table_year;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		} elseif ($units === 'two') {
			if (is_numeric($starting_sec) && is_numeric($ending_sec)) {
				$total_days = calculateDateDifference($start_date, $ending_date);
				if ($total_days <= 0) {
					$this->param['error'] = 'Please! add at least one day.';
					return $this->param;
				}
				$cagr = pow($ending_sec / $starting_sec, 365 / $total_days) - 1;
				$double = log(2, M_E) / log(1 + $cagr, M_E);
				$yearx = floor($double);
				$fractional_part = $double - $yearx;
				$total_dayz = $fractional_part * 365;
				$monthz = floor($total_dayz / 30);
				$dayz = round($total_dayz % 30);
				$table_year = round($total_days / 365);
				$cagr_percentage = $cagr * 100;
				$this->param['total_days'] = $total_days;
				$this->param['cagr_percentage'] = $cagr_percentage;
				$this->param['dayz'] = $dayz;
				$this->param['monthz'] = $monthz;
				$this->param['yearx'] = $yearx;
				$this->param['table_year'] = $table_year;
			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} elseif ($units === 'three') {
			if (is_numeric($starting_third) && is_numeric($cagr)) {
				$total_days = calculateTotalDays($years_third, $months_third, $days_third) / 365;
				if ($total_days <= 0) {
					$this->param['error'] = 'Please! add at least one day.';
					return $this->param;
				}
				if ($cagr <= 0) {
					$this->param['error'] = 'Please! Check Your CAGR Input.';
					return $this->param;
				}
				$cagr_percentage = $starting_third * pow((1 + $cagr / 100), ($total_days));
				$double = log(2, M_E) / log(1 + $cagr, M_E);
				$yearx = floor($double);
				$fractional_part = $double - $yearx;
				$total_dayz = $fractional_part * 365;
				$monthz = floor($total_dayz / 30);
				$dayz = round($total_dayz % 30);

				if ($years_third <= "1") {
					$year = $years_third . " year";
				} else {
					$year = $years_third . " years";
				}
				if ($months_third <= "1") {
					$months = $months_third . " month";
				} else {
					$months = $months_third . " months";
				}
				if ($days_third <= "1") {
					$days = $days_third . " day";
				} else {
					$days = $days_third . " days";
				}
				$this->param['cagr_percentage'] = $cagr_percentage;
				$this->param['dayz'] = $dayz;
				$this->param['monthz'] = $monthz;
				$this->param['yearx'] = $yearx;
				$this->param['total_days'] = $total_days;
				$this->param['year'] = $year;
				$this->param['months'] = $months;
				$this->param['days'] = $days;
				// dd($this->param);

			} else {
				$this->param['error'] = 'Please fill all fields.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'Please fill all fields.';
			return $this->param;
		}
		$this->param['RESULT'] = 1;
		return $this->param;
	}

	/**********************
		ROI Caluclator
	 **********************/
	public function roi($request)
	{
		// dd($request->all());

		$invest = $request->invest;
		$return = $request->return;
		$find = $request->find;
		$annualized = $request->annualized;
		$date = $request->date;
		$s_date = $request->s_date;
		$e_date = $request->e_date;
		$length = $request->length;
		$length_units = $request->length_unit;
		$compare = $request->compare;
		$invest_compare = $request->invest_compare;
		$return_compare = $request->return_compare;
		$find_compare = $request->find_compare;
		$annualized_compare = $request->annualized_compare;
		$date_compare = $request->date_compare;
		$s_date_compare = $request->s_date_compare;
		$e_date_compare = $request->e_date_compare;
		$length_compare = $request->length_compare;
		$length_unit_compares = $request->length_unit_compare;

		if ($length_unit_compares == 'days') {
			$length_unit_compare = '1';
		} else if ($length_unit_compares == 'weeks') {
			$length_unit_compare = '2';
		} else if ($length_unit_compares == 'months') {
			$length_unit_compare = '3';
		} else if ($length_unit_compares == 'years') {
			$length_unit_compare = '4';
		}

		if ($length_units == 'days') {
			$length_unit = '1';
		} else if ($length_units == 'weeks') {
			$length_unit = '2';
		} else if ($length_units == 'months') {
			$length_unit = '3';
		} else if ($length_units == 'years') {
			$length_unit = '4';
		}

		function years($a, $b)
		{
			if ($b == "1") {
				$convert = $a / 365;
			} elseif ($b == "2") {
				$convert = $a / 12;
			} elseif ($b == "3") {
				$convert = $a / 52.143;
			} elseif ($b == "4") {
				$convert = $a * 1;
			}
			return $convert;
		}
		function dateDiffInDays($date1, $date2)
		{
			// Calculating the difference in timestamps
			$diff = strtotime($date2) - strtotime($date1);

			// 1 day = 24 hours
			// 24 * 60 * 60 = 86400 seconds
			return abs(round($diff / 86400));
		}

		if (!($invest <= 0)) {
			if (!($return <= 0)) {
				$answer = $return - $invest;
				if ($answer >= 0) {
					$loss = "0.00";
					$gain = $answer;
				} else if ($answer < 0) {
					$loss = -1 * $answer;
					$gain = "0.00";
				}
				$a1 = $answer / $invest;
				$roi = $a1 * 100;
				if ($find == "1") {
					if ($date == "1") {
						$from = date('M d, Y', strtotime($s_date));
						$to = date('M d, Y', strtotime($e_date));
						if (strtotime($s_date) > strtotime($e_date)) {
							$new = $from;
							$from = $to;
							$to = $new;
						}
						$this->param['from'] = $from;
						$this->param['to'] = $to;
						$days = dateDiffInDays($from, $to);
						$yrs = $days / 365;
						$top_n = 1 / $yrs;
						$inner1 = 1 + $a1;
						$outer = pow($inner1, $top_n);
						$annual_ans = $outer - 1;
						$annualized_answer = $annual_ans * 100;
						$time = $yrs;
					} else if ($date == "2") {
						if ($length != 0) {
							$length = years($length, $length_unit);
							$n_top = 1 / $length;
							$inner = 1 + $a1;
							$final = pow($inner, $n_top);
							$annualized_ans1 = $final - 1;
							$annualized_answer = $annualized_ans1 * 100;
							$time = $length;
						} else {
							$this->param['error'] = 'Investment Length cannot be zero.';
							return $this->param;
						}
					}
					$annualized_answer = number_format($annualized_answer, 4);
					$this->param['annualized_answer'] = $annualized_answer;
				} else if ($find == "2") {
					$annual = $annualized / 100;
					$plus_roi = 1 + $a1;
					$left = $annual + 1;
					$log_left = log($left);
					$log_right = log($plus_roi);


					if ($log_right == '0.0') {
						$ans = '0';
					} else {
						$ans = $log_left / $log_right;
					}

					if ($ans == '0.0') {
						$time = '0';
					} else {
						$time = 1 / $ans;
					}
				}
			} else {
				$this->param['error'] = 'The minimum returned amount is 0.';
				return $this->param;
			}
		} else {
			$this->param['error'] = 'You have to invest some money!';
			return $this->param;
		}
		if ($compare == "2") {
			if (!($invest_compare <= 0)) {
				if (!($return_compare <= 0)) {
					$answer2 = $return_compare - $invest_compare;
					if ($answer2 >= 0) {
						$loss2 = "0.00";
						$gain2 = $answer2;
					} else if ($answer2 < 0) {
						$loss2 = -1 * $answer2;
						$gain2 = "0.00";
					}
					$a12 = $answer2 / $invest_compare;
					$roi2 = $a12 * 100;
					if ($find_compare == "1") {
						if ($date_compare == "1") {
							$from2 = date('M d, Y', strtotime($s_date_compare));
							$to2 = date('M d, Y', strtotime($e_date_compare));
							if (strtotime($s_date_compare) > strtotime($e_date_compare)) {
								$new2 = $from2;
								$from2 = $to2;
								$to2 = $new2;
							}
							$this->param['from2'] = $from2;
							$this->param['to2'] = $to2;
							$days2 = dateDiffInDays($from2, $to2);
							$yrs2 = $days2 / 365;
							$top_n2 = 1 / $yrs2;
							$inner12 = 1 + $a12;
							$outer2 = pow($inner12, $top_n2);
							$annual_ans2 = $outer2 - 1;
							$annualized_answer2 = $annual_ans2 * 100;
							$time2 = $yrs2;
						} else if ($date_compare == "2") {
							if ($length_compare != 0) {
								$length_compare = years($length_compare, $length_unit_compare);
								$n_top2 = 1 / $length_compare;
								$inner2 = 1 + $a12;
								$final2 = pow($inner2, $n_top2);
								$annualized_ans12 = $final2 - 1;
								$annualized_answer2 = $annualized_ans12 * 100;
								$time2 = $length_compare;
							} else {
								$this->param['error'] = 'Investment Length cannot be zero.';
								return $this->param;
							}
						}
						$annualized_answer2 = number_format($annualized_answer2, 4);
						$this->param['annualized_answer2'] = $annualized_answer2;
					} else if ($find_compare == "2") {
						$annual2 = $annualized_compare / 100;
						$plus_roi2 = 1 + $a12;
						$left2 = $annual2 + 1;
						$log_left2 = log($left2);
						$log_right2 = log($plus_roi2);
						$ans2 = $log_left2 / $log_right2;
						$time2 = 1 / $ans2;
					}
				} else {
					$this->param['error'] = 'The minimum returned amount is 0.';
					return $this->param;
				}
			} else {
				$this->param['error'] = 'You have to invest some money!.';
				return $this->param;
			}
			$time2 = number_format($time2, 3);
			$answer2 = number_format($answer2, 2);
			$this->param['time2'] = $time2;
			$this->param['time'] = $time;
			$this->param['loss2'] = $loss2;
			$this->param['loss'] = $loss;
			$this->param['gain2'] = $gain2;
			$this->param['gain'] = $gain;
			$this->param['roi2'] = $roi2;
			$this->param['roi'] = $roi;
			$this->param['compare'] = $compare;
			$this->param['date_compare'] = $date_compare;
			$this->param['find_compare'] = $find_compare;
			$this->param['from'] = $s_date_compare;
			$this->param['to'] = $e_date_compare;
			// dd($this->param);

			return $this->param;
		}


		$time = number_format($time, 3);
		$answer = number_format($answer, 2);
		$this->param['time'] = $time;
		$this->param['loss'] = $loss;
		$this->param['gain'] = $gain;
		$this->param['roi'] = $roi;
		$this->param['compare'] = $compare;
		$this->param['find'] = $find;
		$this->param['date'] = $date;
		$this->param['RESULT'] = 1;
		// dd($this->param);	 	
		return $this->param;
	}


	/*******************
		Discounted Cash Flow Calculator
	 *******************/
	function discounted($request)
	{
	// dd($request->all());
		$main_unit = trim($request->main_unit);
		$input = $request->input;
		$cash = trim($request->cash);
		$outstanding = trim($request->outstanding);
		$perpetual = trim($request->perpetual);
		$wacc = trim($request->wacc);
		$shares = trim($request->shares);
		$price = trim($request->price);
		$earnings = trim($request->earnings);
		$discount = trim($request->discount);
		$growth = trim($request->growth);
		$growth_time = trim($request->growth_time);
		$growth_time_one = trim($request->growth_time_one);
		$growth_time_sec = trim($request->growth_time_sec);
		$growth_unit = trim($request->growth_unit);
		$terminal = trim($request->terminal);
		$terminal_time = trim($request->terminal_time);
		$terminal_one = trim($request->terminal_one);
		$terminal_sec = trim($request->terminal_sec);
		$terminal_unit = trim($request->terminal_unit);


		if ($main_unit === "Earnings per share (EPS)") {
			if (empty($growth_time_one) && empty($growth_time_sec)) {
				$this->param['error'] = 'Please! Enter Input.';
				return $this->param;
			}
			if (empty($growth_time_one)) {
				$growth_time_one = 0;
			}
			if (empty($growth_time_sec)) {
				$growth_time_sec = 0;
			}
			if (empty($terminal_one) && empty($terminal_sec)) {
				$this->param['error'] = 'Please! Enter Input.';
				return $this->param;
			}
			if (empty($terminal_one)) {
				$terminal_one = 0;
			}
			if (empty($terminal_sec)) {
				$terminal_sec = 0;
			}
			if (is_numeric($earnings) && is_numeric($discount) && is_numeric($growth) && is_numeric($growth_time) && is_numeric($terminal) && is_numeric($terminal_time)) {
				if ($terminal_unit === "yrs/mos") {
					$terminal_time = ($terminal_one) + ($terminal_sec / 12);
				}
				if ($growth_unit === "yrs/mos") {
					$growth_time = ($growth_time_one) + ($growth_time_sec / 12);
				} else if ($growth_unit === "mos") {
					$growth_time = $growth_time / 12;
				} else {
					$growth_time = $growth_time;
				}
				if ($terminal_unit === "mos") {
					$terminal_time = $terminal_time  / 12;
				} else {
					$terminal_time = $terminal_time;
				}
				$coefficient = (1 + ($growth / 100)) / (1 + ($discount / 100));

				if ($discount == 0) {
					$this->param['error'] = 'discount rate Value is greater than or not equal to.';
					return $this->param;
				}
				//Growth value
				$groeth_answer = $earnings * $coefficient * (1 - pow($coefficient, $growth_time)) / (1 - $coefficient);
				$coefficient_b = (1 + ($terminal / 100)) / (1 + ($discount / 100));
				//terminal value

				$terminal_answer = ($earnings * pow($coefficient, $growth_time) * $coefficient_b * (1 - pow($coefficient_b, $terminal_time))) / (1 - $coefficient_b);
				//Total intrinsic value
				$Total_intrinsic_answer = $groeth_answer + $terminal_answer;

				$this->param['groeth_answer'] = $groeth_answer;
				$this->param['terminal_answer'] = $terminal_answer;
				$this->param['Total_intrinsic_answer'] = $Total_intrinsic_answer;
				$this->param['main_unit'] = $main_unit;
				$this->param['growth_unit'] = $growth_unit;
				$this->param['terminal_unit'] = $terminal_unit;
				$this->param['input'] = $input;
				$this->param['length'] = count($this->param['input']) + 1;

				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		} else {

			if (is_numeric($cash) && is_numeric($outstanding) && $perpetual && $wacc && is_numeric($shares) && is_numeric($price)  && is_numeric($growth_time_one)  && is_numeric($growth_time_sec)  && is_numeric($terminal_one) && is_numeric($terminal_sec) && $terminal_unit && $growth_unit) {

				$nawi_array = [];
				for ($i = 0; $i < count($input); $i++) {
					if (is_numeric($input[$i])) {
						$nawi_array[$i + 1] = $input[$i];
					}
				}

				if (count($nawi_array) < 1) {
					$this->param['error'] = 'Please! Check Your Input.';
					return $this->param;
				}
				$fcff_last = end($nawi_array);

				//The terminal value 

				if ($wacc == 0) {
					$this->param['error'] = 'wacc value is greater than or not equal to.';
					return $this->param;
				}
				$terminal_value = $fcff_last * (1 + ($perpetual / 100)) / (($wacc / 100) - ($perpetual / 100));
				$nz = count($nawi_array);
				function calculateFirmValue($fcffArray, $wacc)
				{
					$firmValue = 0;
					foreach ($fcffArray as $t => $fcff) {
						$discountFactor = pow(1 + ($wacc / 100), $t);
						$firmValue += $fcff / $discountFactor;
					}
					return $firmValue;
				}
				$result = calculateFirmValue($nawi_array, $wacc);
				$value_firm = pow((1 + ($wacc / 100)), $nz);
				$ans_sec = $terminal_value / $value_firm;
				////answerr
				$answer_sec = $result + $ans_sec;
				$net_debt = $outstanding - $cash;
				//aswers
				$equdiry = $answer_sec - $net_debt;
				//aswers
				if ($shares == 0) {
					$this->param['error'] = 'Outstanding Shares value is greater than or not equal to.';
					return $this->param;
				}
				$fair_val = $equdiry / $shares;
				if ($fair_val == 0) {
					$this->param['error'] = 'fair value is greater than or not equal to.';
					return $this->param;
				}
				//aswers
				$percentage = (($price - $fair_val) * 100) / $fair_val;

				$this->param['terminal_value'] = $terminal_value;
				$this->param['answer_sec'] = $answer_sec;
				$this->param['equdiry'] = $equdiry;
				$this->param['fair_val'] = $fair_val;
				$this->param['percentage'] = $percentage;
				$this->param['main_unit'] = $main_unit;
				$this->param['input'] = $input;
				$this->param['growth_unit'] = $growth_unit;
				$this->param['terminal_unit'] = $terminal_unit;
				$this->param['length'] = count($this->param['input']) + 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input.';
				return $this->param;
			}
		}
		// $this->param['cost_basis'] = $cost_basis;
		$this->param['RESULT'] = 1;
		return $this->param;
	}

