					$this->param['error'] = 'Please fill All fields.';
					return $this->param;
				}
			}
		}
	}

	/*******************
   	Employee Cost Calculator
	 *******************/
	function employee($request)
	{
		// dd($request->all());
		$submit = trim($request->unit_type);
		$rate = trim($request->rate);
		$hour_worked = trim($request->hour_worked);
		$month = trim($request->month);
		$benefits = trim($request->benefits) ?: 0;
		$health = trim($request->health) ?: 0;
		$dental = trim($request->dental) ?: 0;
		$vision = trim($request->vision) ?: 0;
		if (isset($request->perk_name) && isset($request->annual_contribution)) {
			$perk_name = $request->perk_name;
			$annual_contribution = $request->annual_contribution;
		}
		function calculatePerk($perk_name, $annual_contribution)
		{
			$perk = 0;
			$length_perk = count($perk_name);
			$length_annual = count($annual_contribution);
			$name_array = array();

			for ($y = 0; $y < $length_perk && $y < $length_annual; $y++) {
				$name_array[] = $perk_name[$y];
				$perk_val[] = $annual_contribution[$y];
				$perk += $annual_contribution[$y];
			}

			return [$name_array, $perk, $perk_val];
		}

		if ($submit == 'hourly') {

			if (is_numeric($request->rate) && is_numeric($request->month)) {

				if (isset($perk_name) && isset($annual_contribution)) {
					[$name_array, $perk, $perk_val] = calculatePerk($perk_name, $annual_contribution);
				}
				if (is_numeric($rate) && is_numeric($hour_worked) && is_numeric($month)) {
					$emp_rate = $rate * 4.66484 * $hour_worked * $month;
					$emp_h_r = $emp_rate + $benefits + $health + $dental + $vision;
					if (isset($perk_name) && isset($annual_contribution)) {
						$emp_h_r_p =	$emp_h_r + $perk;
						$this->param['emp_h_r_p'] = $emp_h_r_p;
					}
					$this->param['emp_h_r'] = $emp_h_r;
					$this->param['rate'] = $rate;
					$this->param['hour_worked'] = $hour_worked;
					$this->param['benefits'] = $benefits;
					$this->param['health'] = $health;
					$this->param['dental'] = $dental;
					$this->param['vision'] = $vision;
					$this->param['month'] = $month;
					$this->param['emp_rate'] = $emp_rate;
					if (isset($perk_name) && isset($annual_contribution)) {
						$this->param['perk_array'] = $name_array;
						$this->param['perk'] = $perk;
						$this->param['perk_val'] = $perk_val;
					}
				} else {
					$this->param['error'] = 'Please Enter two values.';
					return $this->param;
				}
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		} else if ($submit == 'salary') {
			if (is_numeric($request->rate) && is_numeric($request->hour_worked) && is_numeric($request->month)) {

				if (isset($perk_name) && isset($annual_contribution)) {
					[$name_array, $perk, $perk_val] = calculatePerk($perk_name, $annual_contribution);
				}
				if (is_numeric($rate) && is_numeric($month)) {
					$per_anum = $rate * 0.0765;
					$anual_salary = $per_anum + $rate + $benefits + $health + $dental + $vision;
					if (isset($perk_name) && isset($annual_contribution)) {
						$emp_h_r_p =	$anual_salary + $perk;
						$this->param['emp_h_r_p'] = $emp_h_r_p;
					}
					$this->param['anual_salary'] = $anual_salary;
					$this->param['rate'] = $rate;
					$this->param['per_anum'] = $per_anum;
					$this->param['benefits'] = $benefits;
					$this->param['health'] = $health;
					$this->param['dental'] = $dental;
					$this->param['vision'] = $vision;
					if (isset($perk_name) && isset($annual_contribution)) {
						$this->param['perk_array'] = $name_array;
						$this->param['perk'] = $perk;
						$this->param['perk_val'] = $perk_val;
					}
				}
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		}
		$this->param['RESULT'] = 1;
		$this->param['submit'] = $submit;
		// dd($this->param);
		return $this->param;
	}


	function payback($request)
	{
		//  dd($request->all());
		if ($request->unit_type == 'same') {
			if (is_numeric($request->initial) && is_numeric($request->cash) && is_numeric($request->in_de) && is_numeric($request->year) && is_numeric($request->discount)) {
				if ($request->year <= 100) {
					$total = $request->initial;
					$in_de = $request->in_de;
					$years = $request->year;
					$discount = $request->discount;
					$cash = $request->cash;
					$cash_ = $request->cash;
					$cdcf = $request->initial * (-1);
					$cdcf_ = $request->initial * (-1);
					// to save inputs
					$put_input['initial'] = $request->initial;
					$put_input['in_de'] = $request->in_de;
					$put_input['year'] = $request->year;
					$put_input['discount'] = $request->discount;
					$put_input['cash'] = $request->cash;
					$put_input['initial'] = $request->initial;
					date_default_timezone_set('Asia/Karachi');
					$put_input['time'] = date('j-m-Y, H:i:s');
					$save_input[] = $put_input;
					$table = '';
					$com = 0;
					for ($i = 1; $i <= $years; $i++) {
						if ($i !== 1) {
							if ($request->add_sub === 'in') {
								$cash = $cash + ($cash * ($in_de / 100));
							} else {
								$cash = $cash - ($cash * ($in_de / 100));
							}
						}
						$pv = $cash / pow((1 + ($discount / 100)), $i);
						$com = $com + $pv;
						$table .= "<tr><td class='py-2 border-b'>Year $i</td><td class='py-2 border-b'>" . $request->currency . number_format($cash, 2) . "</td><td class='py-2 border-b'>" . $request->currency . number_format($cdcf + $cash, 2) . "</td><td class='py-2 border-b'>" . $request->currency . number_format($pv, 2) . "</td><td class='py-2 border-b'>" . $request->currency . number_format($cdcf_ + $pv, 2) . "</td></tr>";
						$cdcf = $cdcf + $cash;
						$cdcf_ = $cdcf_ + $pv;
					}
					$com = $com / $years;
					$percent = round(($com / $total) * 100, 3);
					$i = 1;
					$cash = $request->cash;
					$cdcf = 0;
					while ($request->initial > $cdcf) {
						if ($i !== 1) {
							if ($request->add_sub === 'in') {
								$cash = round($cash + ($cash * ($in_de / 100)), 2);
							} else {
								$cash = round($cash - ($cash * ($in_de / 100)), 2);
							}
						}
						$pv = $cash / pow((1 + ($discount / 100)), $i);
						$cdcf = $cdcf + $pv;
						if ($cdcf >= $request->initial) {
							$A = $i - 1;
							$B = $request->initial - ($cdcf - $pv);
							$C = $pv;
							$dis_back = round($A + ($B / $C), 3);
						}
						$i++;
					}
					$i = 1;
					$cash = $request->cash;
					$cdcf = 0;
					while ($request->initial > $cdcf) {
						if ($i !== 1) {
							if ($request->add_sub === 'in') {
								$cash = $cash + ($cash * ($in_de / 100));
							} else {
								$cash = $cash - ($cash * ($in_de / 100));
							}
						}
						$pv = $cash;
						$cdcf = $cdcf + $pv;
						if ($cdcf >= $request->initial) {
							$A = $i - 1;
							$B = $request->initial - ($cdcf - $pv);
							$C = $pv;
							$back = round($A + ($B / $C), 3);
						}
						$i++;
					}
					$this->param['back'] = $back;
					$this->param['same'] = $back;
					$this->param['percent'] = $percent;
					$this->param['total'] = $total;
					$this->param['dis_back'] = $dis_back;
					$this->param['table'] = $table;
					$this->param['RESULT'] = 1;
					// dd($this->param);
					return $this->param;
				} else {
					$this->param['error'] = 'Please provide a positive number of years that is 100 or less.';
					return $this->param;
				}
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		} else if ($request->unit_type == 'not_same') {


			if (is_numeric($request->initial2) && is_numeric($request->discount2)) {


				$total = $request->initial2;
				$discount = $request->discount2;
				$cdcf = $request->initial2 * (-1);
				$cdcf_ = $request->initial2 * (-1);

				// to save inputs
				$put_input['initial2'] = $request->initial2;
				$put_input['discount2'] = $request->discount2;
				$put_input['count'] = $request->count;
				date_default_timezone_set('Asia/Karachi');
				$put_input['time'] = date('j-m-Y, H:i:s');
				$save_input[] = $put_input;
				$table = '';
				$com = 0;
				$ave = 0;
				$total_back = 0;
				$distotal_back = 0;
				$ave_dis = 0;
				$ave_i = 0;

				for ($i = 1; $i <= $request->count; $i++) {

					if (is_numeric($i)) {

						$cash = $i;
						$ave = $ave + $cash;
						$ave_i++;
						$pv = $cash / pow((1 + ($discount / 100)), $i);
						$ave_dis = $ave_dis + $pv;
						$table .= "<tr><td class='py-2 border-b'>Year $i</td><td class='py-2 border-b'>" . $request->currency1 . number_format($cash, 2) . "</td><td class='py-2 border-b'>" . $request->currency1 . number_format($cdcf + $cash, 2) . "</td><td class='py-2 border-b'>" . $request->currency1 . number_format($pv, 2) . "</td><td class='py-2 border-b'>" . $request->currency1 . number_format($cdcf_ + $pv, 2) . "</td></tr>";
						$cdcf = $cdcf + $cash;
						$total_back = $total_back + $cash;

						if ($cdcf >= 0 && !isset($back)) {
							$A = $i - 1;
							$B = $request->initial2 - ($total_back - $cash);
							$C = $cash;
							$back = round($A + ($B / $C), 3);

							$back_check = true;
						}
						$cdcf_ = $cdcf_ + $pv;
						$distotal_back = $distotal_back + $pv;
						if ($cdcf_ >= 0 && !isset($dis_back)) {
							$A = $i - 1;
							$B = $request->initial2 - ($distotal_back - $pv);
							$C = $pv;
							$dis_back = round($A + ($B / $C), 3);

							$dis_back_check = true;
						}
					}
				}
				if ($ave_i == "0") {
					$ave_cash = "0";
					$ave_cash_d = "0";
				} else {
					$ave_cash = round($ave / $ave_i, 2);
					$ave_cash_d = round($ave_dis / $ave_i, 2);
				}


				if (!isset($dis_back_check)) {
					$this->param['dis_not_back'] = true;
					$i = 1;
					$cdcf = 0;
					while ($request->initial2 > $cdcf) {
						$cdcf = $cdcf + $ave_cash_d;
						if ($cdcf >= $request->initial2) {
							$A = $i - 1;
							$B = $request->initial2 - ($cdcf - $ave_cash_d);
							$C = $ave_cash_d;
							$dis_back = round($A + ($B / $C), 3);
						}
						$i++;
					}
				}
				if (!isset($back_check)) {
					$this->param['not_back'] = true;
					$i = 1;
					$cdcf = 0;
					while ($request->initial2 > $cdcf) {
						$cdcf = $cdcf + $ave_cash;
						if ($cdcf >= $request->initial2) {
							$A = $i - 1;
							$B = $request->initial2 - ($cdcf - $ave_cash);
							$C = $ave_cash;
							$back = round($A + ($B / $C), 3);
						}
						$i++;
					}
				}
				$this->param['ave_i'] = $ave_i;
				$this->param['ave_cash'] = $ave_cash;
				$this->param['ave_cash_d'] = $ave_cash_d;
				$this->param['back'] = $back;
				$this->param['total'] = $total;
				$this->param['dis_back'] = $dis_back;
				$this->param['table'] = $table;
				$this->param['RESULT'] = 1;
				dd($this->param);
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		}
	}

	function wacc($request)
	{
		// dd($request->all());
		if ($request->unit_type == 'debt') {

			if (is_numeric($request->risk) && is_numeric($request->beta) && is_numeric($request->eq)) {
				$eq = round($request->risk + ($request->beta * $request->eq), 4);
				$this->param['eq'] = $eq;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		} elseif ($request->unit_type == 'cd') {
			if (is_numeric($request->rate) && is_numeric($request->tax)) {
				if (is_numeric($request->risk) && is_numeric($request->beta) && is_numeric($request->eq)) {
					$eq = round($request->risk + ($request->beta * $request->eq), 4);
					$this->param['eq'] = $eq;
				}
				$cd = round(($request->rate / 100) * (1 - ($request->tax / 100)) * 100, 4);
				$this->param['cd'] = $cd;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		} else {
			if (is_numeric($request->a) && is_numeric($request->b) && is_numeric($request->c) && is_numeric($request->d) && is_numeric($request->e)) {
				$check = true;
				$D = $request->a;
				$RD = $request->b / 100;
				$E = $request->c;
				$RE = $request->d / 100;
				$T = $request->e / 100;
				$wacc = round((($E / ($E + $D)) * $RE + ($D / ($E + $D)) * $RD * (1 - $T)) * 100, 4);
				$pfe = round(($E / ($E + $D)) * 100, 4);
				$pfd = round(($D / ($E + $D)) * 100, 4);
				$RD = $RD * 100;
				$RE = $RE * 100;
				$T = $T * 100;
				$this->param['wacc'] = $wacc;
				$this->param['D'] = $D;
				$this->param['RD'] = $RD;
				$this->param['E'] = $E;
				$this->param['RE'] = $RE;
				$this->param['pfe'] = $pfe;
				$this->param['pfd'] = $pfd;
				$this->param['T'] = $T;
				$this->param['RESULT'] = 1;
				// dd($this->param);
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		}
	}

	public function basis($request)
	{
		// dd($request->all());

		$dec = $request->dec;
		$percent = $request->percent;
		$perm = $request->perm;
		$bsp = $request->bsp;
		$submit = $request->unit_type;
		$bps1 = $request->bps1;
		$bps_unit = $request->bps_unit;
		$of = $request->of;
		$equals = $request->equals;

		if ($bps_unit == 'decimal') {
			$bps_unit = '1';
		} else if ($bps_unit == 'percent') {
			$bps_unit = '2';
		} else if ($bps_unit == 'percent') {
			$bps_unit = '3';
		} else if ($bps_unit == 'bps') {
			$bps_unit = '4';
		}

		if ($submit == 'submit') {

			if (is_numeric($dec) && empty($percent) && empty($perm) && empty($bsp)) {
				$percent = $dec * 100;
				$perm = $dec * 1000;
				$bsp = $dec * 10000;
				$this->param['percent'] = $percent;
				$this->param['perm'] = $perm;
				$this->param['bsp'] = $bsp;
				$this->param['ans'] = 1;
				$this->param['RESULT'] = 1;
				return $this->param;
			} elseif (empty($dec) && is_numeric($percent) && empty($perm) && empty($bsp)) {
				$dec = $percent / 100;
				$perm = $percent * 10;
				$bsp = $percent * 100;
				$this->param['dec'] = $dec;
				$this->param['perm'] = $perm;
				$this->param['bsp'] = $bsp;
				$this->param['ans'] = 2;
				$this->param['RESULT'] = 1;
				return $this->param;
			} elseif (empty($dec) && empty($percent) && is_numeric($perm) && empty($bsp)) {
				$dec = $perm / 1000;
				$percent = $perm / 10;
				$bsp = $perm * 10;
				$this->param['dec'] = $dec;
				$this->param['percent'] = $percent;
				$this->param['bsp'] = $bsp;
				$this->param['ans'] = 3;
				$this->param['RESULT'] = 1;
				return $this->param;
			} elseif (empty($dec) && empty($percent) && empty($perm) && is_numeric($bsp)) {
				$dec = $bsp / 10000;
				$percent = $bsp / 100;
				$perm = $bsp / 10;
				$this->param['dec'] = $dec;
				$this->param['perm'] = $perm;
				$this->param['percent'] = $percent;
				$this->param['ans'] = 4;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		} elseif ($submit == 'submit1') {
			if (is_numeric($bps1) && is_numeric($of) && empty($equals)) {
				if ($bps_unit == '1') {
					$bps1 = $bps1 * 10000;
				} elseif ($bps_unit == '2') {
					$bps1 = $bps1 * 100;
				} elseif ($bps_unit == '3') {
					$bps1 = $bps1 * 10;
				}

				$equals = ($bps1 * $of) / 10000;
				$this->param['equals'] = $equals;
				$this->param['of'] = $of;
				$this->param['bps1'] = $bps1;
				$this->param['ans'] = 5;
				$this->param['RESULT'] = 1;

				return $this->param;
			} elseif (is_numeric($bps1) && empty($of) && is_numeric($equals)) {
				if ($bps_unit == '1') {
					$bps1 = $bps1 * 10000;
				} elseif ($bps_unit == '2') {
					$bps1 = $bps1 * 100;
				} elseif ($bps_unit == '3') {
					$bps1 = $bps1 * 10;
				}
				$of = ($equals * 1000) / $bps1;
				$this->param['equals'] = $equals;
				$this->param['of'] = $of;
				$this->param['bps1'] = $bps1;
				$this->param['ans'] = 5;
				$this->param['RESULT'] = 1;

				return $this->param;
			} elseif (empty($bps1) && is_numeric($of) && is_numeric($equals)) {
				$bps1 = ($equals * 10000) / $of;
				$this->param['equals'] = $equals;
				$this->param['of'] = $of;
				$this->param['bps1'] = $bps1;
				$this->param['ans'] = 5;
				$this->param['RESULT'] = 1;
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
			}
		}
	}
	/**********************
		Car depreciation Calculator
	 **********************/
	public function car_dep($request)
	{
		// dd($request->all());
		$car_cost = $request->car_cost;
		$c_age = $request->c_age;
		$car_year = $request->car_year;
		$rate_level = $request->rate_level;
		$hiddent_currency = $request->hiddent_currency;

		$total_book_value = '';
		if (is_numeric($car_cost) && is_numeric($c_age) && !empty($rate_level) && is_numeric($car_year)) {
			$asset = $car_cost;
			$asset1 = $car_cost;
			$depreciation = 0;
			$c_depreciation = 0;
			$table = '';
			$total_years = '';
			for ($i = 1; $i <= $car_year; $i++) {
				if ($rate_level === '1') {
					$rate = 21.40;
				} else if ($rate_level === '2') {
					$rate = 15.60;
				} else {
					$rate = 10.40;
				}
				if ($i == 1 && $c_age === "0") {
					if ($rate_level === "1") {
						$rate = 35.00;
					} else if ($rate_level === "2") {
						$rate = 25.00;
					} else {
						$rate = 16.00;
					}
				}
				$total_years .= $i . ',';
				$depreciation = round(($asset1) * ($rate / 100), 2);
				$c_depreciation = round($c_depreciation + $depreciation, 2);
				$end_book_value = round($asset - $c_depreciation, 2);
				$total_book_value .= $end_book_value . ",";
				$table .= '<tr><td class="py-2 border-b">' . $i . '</td><td class="py-2 border-b"> ' . $hiddent_currency . ' ' . $asset1 . '</td><td class="py-2 border-b">' . $rate . '%</td><td class="py-2 border-b"> ' . $hiddent_currency . ' ' . $depreciation . '</td><td class="py-2 border-b"> ' . $hiddent_currency . ' ' . $c_depreciation . '</td><td class="py-2 border-b"> ' . $hiddent_currency . ' ' . $end_book_value . '</td></tr>';
				$asset1 = $asset - $c_depreciation;
			}
			$this->param['table'] = $table;
			$this->param['car'] = 'active';
			$this->param['total_years'] = $total_years;
			$this->param['total_book_value'] = $total_book_value;
			$this->param['RESULT'] = 1;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
	}

	/**********************
		Property depreciation Calculator
	 **********************/
	function property($request)
	{
		// dd($request->all());
		$basis = $request->basis;
		$recovery = $request->recovery;
		$round = $request->round;
		$date1 = $request->date1;
