	/*******************
		ARV Calculator
	 *******************/
	function arv($request)
	{
		// dd($request->all());
		$method_unit = trim($request->method_unit);
		$property = trim($request->property);
		$area = trim($request->area);
		$area_unit = trim($request->area_unit);
		$value = trim($request->value);
		$total = trim($request->total);
		$total_unit = trim($request->total_unit);
		$average = trim($request->average);
		$average_unit = trim($request->average_unit);
		$cost = trim($request->cost);
		$purchase = trim($request->purchase);

		function arv_units($area, $area_unit)
		{
			if ($area_unit === "m²") {
				// Already in square meters, no conversion needed
				return $area;
			} elseif ($area_unit === "ft²") {
				// Convert square feet to square meters
				return $area * 0.092903;
			} elseif ($area_unit === "yd²") {
				// Convert square yards to square meters
				return $area * 0.836127;
			} elseif ($area_unit === "mi²") {
				// Convert square miles to square meters
				return $area * 2.58999e+6;
			} else {
				// Handle unsupported unit or invalid input
				return "Unsupported unit or invalid input.";
			}
			return $area;
		}

		if (is_numeric($area) && is_numeric($total) && is_numeric($property) && is_numeric($value) && is_numeric($average) && is_numeric($cost) && is_numeric($purchase)) {
			if ($area == 0) {
				$this->param['error'] = 'Average Area Price value cannot be equal to zero';
				return $this->param;
			}
			if ($total == 0) {
				$this->param['error'] = 'total area of the property value cannot be equal to zero';
				return $this->param;
			}
			if ($property == 0) {
				$this->param['error'] = 'property current value cannot be equal to zero';
				return $this->param;
			}
			if ($value == 0) {
				$this->param['error'] = 'value of renovations value cannot be equal to zero';
				return $this->param;
			}
			if ($average == 0) {
				$this->param['error'] = 'repair cost value cannot be equal to zero';
				return $this->param;
			}
			if ($cost == 0) {
				$this->param['error'] = 'total Cost Of renovation value cannot be equal to zero';
				return $this->param;
			}
			if ($purchase == 0) {
				$this->param['error'] = 'investors purchase rule value cannot be equal to zero';
				return $this->param;
			}
			if ($purchase > 100) {
				$this->param['error'] = 'investors purchase rule % cannot exceed 100%.';
				return $this->param;
			}
			if ($method_unit === "Value Of The Property") {
				$after_repair_value = $property + $value; //ans 1 after_repair_value
			} else {
				$areas = arv_units($area, $area_unit);
				$totals = arv_units($total, $total_unit);
				$after_repair_value = $areas * $totals; //ans 1 after_repair_value

			}
			$averages = arv_units($average, $average_unit);
			$requires_repairs = $cost / $averages; //ans 2 after_repair_value
			$maximum_bid_price = $after_repair_value * ($purchase / 100) - $cost; //ans 3 maximum_bid_price
			$percentage = abs($purchase - 100); //ans 5 percentage 
			$roi = ($percentage / 100) * $after_repair_value; //ans 4 roi 


		} else {
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}

		$this->param['after_repair_value'] = $after_repair_value;
		$this->param['requires_repairs'] = $requires_repairs;
		$this->param['maximum_bid_price'] = $maximum_bid_price;
		$this->param['percentage'] = $percentage;
		$this->param['roi'] = $roi;
		$this->param['RESULT'] = 1;
		// dd($this->param);
		return $this->param;
	}
	/*******************
		opportunity Calculator
	*******************/
	function opportunity($request){

		$return_best = trim($request->return_best);
		$return_choose = trim($request->return_choose);

		if(is_numeric($return_best) && is_numeric($return_choose)){
			$OpportunityCost = $return_best - $return_choose;
		}else{
			$this->param['error'] = 'Please! Check Your Input';
			return $this->param;
		}
		$this->param['OpportunityCost'] = $OpportunityCost;
		$this->param['return_best'] = $return_best;
		$this->param['return_choose'] = $return_choose;
		$this->param[ 'RESULT' ] = 1;
		return $this->param;
	}

	function tip($request)
	{
		// dd($request->all());
		$for = $request->input('for');
		$bill = $request->input('x');
		$xs = $request->input('xs');
		$tip = $request->input('y');
		$person = $request->input('z');
		$round = $request->input('round');
		$rounds = $request->input('rounds');
		if ($for === 'single') {
			if (is_numeric($xs)) {
				$this->param['RESULT'] = 1;
				$this->param['single'] = 1;
				// dd($this->param);
				return true;
			} else {
				$this->param['error'] = 'Please! Fill all the Input Fields';
				return $this->param;
			}
		} else {
			if (is_numeric($bill) && is_numeric($tip) && is_numeric($person)) {
				if ($round == 'yes') {
					$a = round(($tip / 100) * $bill);
					$b = round($bill + $a);
					$c = round($a / $person);
					$d = round($b / $person);
				} else {
					$a = round(($tip / 100) * $bill, 2);
					$b = round($bill + $a, 2);
					$c = round($a / $person, 2);
					$d = round($b / $person, 2);
				}
				$this->param['a'] = $a;
				$this->param['b'] = $b;
				$this->param['c'] = $c;
				$this->param['d'] = $d;
				$this->param['RESULT'] = 1;
				// dd($this->param);
				return $this->param;
			} else {
				$this->param['error'] = 'Please! Fill all the Input Fields';
				return $this->param;
			}
		}
	}
		// Hourly to Salary Calculator
	public function hourly($request){
		// dd($request->all());
		$first = $request->input('first');
		$second = $request->input('second');
		$third = $request->input('third');
		$car = $request->input('car');
	    if (is_numeric($first) && is_numeric($second) && is_numeric($third)) {
	        $annuly  =	$first * $second * $third;
	        $weekly  = $first * $second;
	        $monthly = $annuly / 12;
	    }else{
	        $this->param['error'] = 'Please! Check Your Input';
	        return  $this->param;
	    }
	    $this->param['annuly']	= $annuly;
	    $this->param['weekly'] 	= $weekly;
	    $this->param['monthly'] = $monthly;
	    $this->param['car'] 	= $car;
	    $this->param['RESULT'] 	= 1;
		// dd($this->param);
	    return  $this->param;
	}
	// Salary to Hourly Calculator
	function salarytohur($request){
		// dd($request->all());
		$salary          	= $request->input('salary');
		$hweek           	= $request->input('hweek');
		$hyear				= $request->input('hyear');
		$type            	= $request->input('type');
		$currency           = $request->input('currency');
		if(is_numeric($salary) && is_numeric($hweek) && is_numeric($hyear) && !empty($type)){
			if($currency == '$'){
				$median_sal =53924;
				$name = 'Of US Median';
			}else if($currency == '£'){
				$median_sal =31285;
				$name = 'Of UK Median';
			}else{
				$median_sal = 53924;
				$name = '';
			}	
			if ($hweek > 0 && $hyear > 0 && $salary > 0) {
				if ($type == 'an') {
					$weekly_rate = ($salary / $hyear);
					$hourly_rate = ($weekly_rate / $hweek);
					$monthaly_rate = ($salary / 12);
					$mean = ($salary/$median_sal) * 100;
				} elseif ($type == 'mo') {
					$monthaly_rate = $salary;
					$hourly_rate = (($monthaly_rate * 12) / $hyear) / $hweek;
					$weekly_rate = ($hourly_rate * $hweek);
					$mean = ($salary /$median_sal) * 100;
				} elseif ($type == 'we') {
					$weekly_rate = $salary;
					$hourly_rate = $weekly_rate / $hweek;
					$monthaly_rate = (($hourly_rate * $hyear) * $hweek) / 12;
					$mean = ($salary /$median_sal) * 100;	
				} elseif ($type == 'da') {
					$hourly_rate = $salary / ($hweek / 5);
					$weekly_rate = $hourly_rate * $hweek;
					$monthaly_rate = (($hourly_rate * $hyear) * $hweek) / 12;
					$mean = ($salary /$median_sal) * 100;
				}
				
			} else {
				$this->param['error'] = 'Please! Enter the Correct Value';
				return $this->param;
			}
				$this->param['hourly_rate']			= $hourly_rate;
				$this->param['weekly_rate'] 	  	= $weekly_rate;
				$this->param['monthaly_rate'] 	  = $monthaly_rate;
				$this->param['mean'] = $mean;
				$this->param['name'] = $name;
				$this->param['currency'] = $currency;
				$this->param['RESULT'] 	  = 1;
				// dd($this->param);
				return $this->param;
			}else{
				$this->param['error'] = 'Please! Check Your Input';
				return $this->param;
		}
	}

	
// rent spiit
public function rent_split($request)
{
	// dd($request->all());
	$total_rent = $request->input('total_rent');
	// $currency   = $request->input('currency');
	$total_area = $request->input('total_area');
	$bedrooms   = $request->input('bedrooms');
	$room_area  = $request->input('room_area');
	$persons    = $request->input('persons');
	$bath       = $request->input('bath');
	// dd($request->input());
	if (is_numeric($total_rent) && is_numeric($total_area) && !empty($bedrooms) && !empty($persons) && !empty($room_area) && !empty($bath)) {
		if ($total_area >= array_sum($room_area)) {

			$common_area = $total_area - array_sum($room_area) - array_sum($bath);
			$rent_per_sq =  $total_rent / ($total_area - $common_area);

			for ($i = 1; $i <= $bedrooms; $i++) {
				$room_rent[$i] = (($room_area[$i] +  $bath[$i]) * $rent_per_sq) / $persons[$i];
			}
			$this->param['room_rent'] = $room_rent;
			$this->param['RESULT'] 	  = 1;
			// dd($this->param);
			return $this->param;
		} else {
			$this->param['error'] = 'Combined square footage of rooms should not exceed total square footage of house';
			return $this->param;
		}
	} else {
		$this->param['error'] = 'Please! Check Your Input';
		return $this->param;
	}
}

